/**
 * selfMonitor.ts — Autonomous Self-Monitoring System
 *
 * Runs in the background, tracking error rates, response quality metrics,
 * and performance trends. When degradation is detected, it auto-triggers
 * self-improvement proposals via selfImprove.ts.
 *
 * Integrations:
 *   - selfImprove.ts: Auto-triggers analyzeAndPropose when thresholds are exceeded
 *   - memory.ts: Stores monitoring insights as persistent memories
 *   - goalManager.ts: Can create improvement goals when systemic issues are found
 */

import { randomUUID } from "crypto";
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

// ─── Types ────────────────────────────────────────────────────────────────────

export type MetricType =
  | "error_rate"          // Percentage of requests that error
  | "response_latency"    // Average response time in ms
  | "truncation_rate"     // Percentage of responses that get truncated
  | "tool_failure_rate"   // Percentage of tool calls that fail
  | "user_satisfaction"   // Derived from follow-up patterns
  | "memory_usage"        // Memory store size
  | "self_modify_success" // Self-modification success rate (0 = fail, 1 = success)
  | "self_modify_rollback"// Self-modification rollback rate
  | "proposal_quality"    // Self-improvement proposal acceptance rate
  | "custom";

export type MetricSample = {
  id: string;
  type: MetricType;
  value: number;
  timestamp: number;
  context?: string;       // Optional context about what caused this sample
};

export type MonitorAlert = {
  id: string;
  type: MetricType;
  severity: "info" | "warning" | "critical";
  message: string;
  currentValue: number;
  threshold: number;
  trend: "rising" | "falling" | "stable";
  triggered: boolean;     // Whether an auto-improvement was triggered
  createdAt: number;
  resolvedAt?: number;
};

export type MonitorConfig = {
  enabled: boolean;
  checkIntervalMs: number;         // How often to check metrics (default: 5 min)
  windowSizeMs: number;            // Rolling window for metric calculation (default: 1 hour)
  minSamplesForAlert: number;      // Minimum samples before alerting (default: 10)
  autoTriggerImprovement: boolean; // Whether to auto-trigger self-improvement
  thresholds: {
    error_rate: number;            // Alert when error rate exceeds this (0-1, default: 0.15)
    response_latency: number;      // Alert when avg latency exceeds this (ms, default: 30000)
    truncation_rate: number;       // Alert when truncation rate exceeds this (0-1, default: 0.25)
    tool_failure_rate: number;     // Alert when tool failure rate exceeds this (0-1, default: 0.20)
    self_modify_rollback: number;  // Alert when rollback rate exceeds this (0-1, default: 0.20)
  };
  cooldownMs: number;              // Min time between auto-improvement triggers (default: 30 min)
};

export type HealthReport = {
  status: "healthy" | "degraded" | "critical";
  metrics: Record<MetricType, { current: number; trend: "rising" | "falling" | "stable"; samples: number }>;
  activeAlerts: MonitorAlert[];
  lastCheck: number;
  uptime: number;
  totalSamples: number;
  improvementsTriggered: number;
};

// ─── Storage ──────────────────────────────────────────────────────────────────

const samples: MetricSample[] = [];
const alerts: MonitorAlert[] = [];
const MAX_SAMPLES = 10000;
const MAX_ALERTS = 500;
let improvementsTriggered = 0;
let lastImprovementTrigger = 0;
let monitorStartTime = Date.now();
let lastCheckTime = 0;
let monitorInterval: ReturnType<typeof setInterval> | null = null;
let persistInterval: ReturnType<typeof setInterval> | null = null;

// v5.32: Metrics persistence
const PERSIST_INTERVAL_MS = 5 * 60 * 1000; // Persist every 5 minutes

function getMetricsPath(): string {
  const serverDir = path.dirname(fileURLToPath(import.meta.url));
  const workspaceDir = path.resolve(serverDir, "..", "workspace");
  if (!fs.existsSync(workspaceDir)) fs.mkdirSync(workspaceDir, { recursive: true });
  return path.join(workspaceDir, ".andromeda_monitor_metrics.json");
}

function persistMetrics(): void {
  try {
    const data = {
      samples: samples.slice(-1000), // Persist last 1000 samples
      alerts: alerts.slice(-100),
      improvementsTriggered,
      lastImprovementTrigger,
      monitorStartTime,
      persistedAt: Date.now(),
    };
    const metricsPath = getMetricsPath();
    const tmpPath = metricsPath + ".tmp";
    fs.writeFileSync(tmpPath, JSON.stringify(data, null, 2));
    fs.renameSync(tmpPath, metricsPath); // Atomic write
  } catch (err) {
    console.warn(`[SelfMonitor] Failed to persist metrics: ${(err as Error).message}`);
  }
}

function loadPersistedMetrics(): void {
  try {
    const metricsPath = getMetricsPath();
    if (!fs.existsSync(metricsPath)) return;
    const data = JSON.parse(fs.readFileSync(metricsPath, "utf-8"));
    if (data.samples && Array.isArray(data.samples)) {
      // Only load samples from the last 24 hours
      const cutoff = Date.now() - 24 * 60 * 60 * 1000;
      const recentSamples = data.samples.filter((s: MetricSample) => s.timestamp > cutoff);
      samples.push(...recentSamples);
      console.log(`[SelfMonitor] Loaded ${recentSamples.length} persisted metrics (${data.samples.length - recentSamples.length} expired)`);
    }
    if (data.alerts && Array.isArray(data.alerts)) {
      alerts.push(...data.alerts.slice(-50));
    }
    if (typeof data.improvementsTriggered === "number") {
      improvementsTriggered = data.improvementsTriggered;
    }
  } catch (err) {
    console.warn(`[SelfMonitor] Failed to load persisted metrics: ${(err as Error).message}`);
  }
}

const defaultConfig: MonitorConfig = {
  enabled: true,
  checkIntervalMs: 5 * 60 * 1000,     // 5 minutes
  windowSizeMs: 60 * 60 * 1000,        // 1 hour
  minSamplesForAlert: 10,
  autoTriggerImprovement: true,
  thresholds: {
    error_rate: 0.15,
    response_latency: 30000,
    truncation_rate: 0.25,
    tool_failure_rate: 0.20,
    self_modify_rollback: 0.20,
  },
  cooldownMs: 30 * 60 * 1000,          // 30 minutes
};

let config: MonitorConfig = { ...defaultConfig };

// ─── Metric Recording ─────────────────────────────────────────────────────────

/**
 * Record a metric sample. Call this from anywhere in the codebase.
 */
export function recordMetric(type: MetricType, value: number, context?: string): MetricSample {
  const sample: MetricSample = {
    id: randomUUID(),
    type,
    value,
    timestamp: Date.now(),
    context,
  };
  samples.push(sample);
  if (samples.length > MAX_SAMPLES) samples.splice(0, samples.length - MAX_SAMPLES);
  return sample;
}

/**
 * Record a request outcome (convenience wrapper).
 */
export function recordRequestOutcome(opts: {
  success: boolean;
  latencyMs: number;
  truncated?: boolean;
  toolFailures?: number;
  totalToolCalls?: number;
  context?: string;
}): void {
  recordMetric("error_rate", opts.success ? 0 : 1, opts.context);
  recordMetric("response_latency", opts.latencyMs, opts.context);
  if (opts.truncated !== undefined) {
    recordMetric("truncation_rate", opts.truncated ? 1 : 0, opts.context);
  }
  if (opts.toolFailures !== undefined && opts.totalToolCalls !== undefined && opts.totalToolCalls > 0) {
    recordMetric("tool_failure_rate", opts.toolFailures / opts.totalToolCalls, opts.context);
  }
}

// ─── Metric Calculation ───────────────────────────────────────────────────────

function getSamplesInWindow(type: MetricType, windowMs?: number): MetricSample[] {
  const cutoff = Date.now() - (windowMs ?? config.windowSizeMs);
  return samples.filter(s => s.type === type && s.timestamp >= cutoff);
}

function calculateMetric(type: MetricType): { current: number; trend: "rising" | "falling" | "stable"; samples: number } {
  const windowSamples = getSamplesInWindow(type);
  if (windowSamples.length === 0) return { current: 0, trend: "stable", samples: 0 };

  const current = windowSamples.reduce((sum, s) => sum + s.value, 0) / windowSamples.length;

  // Constants for trend calculation
  const MIN_SAMPLES_FOR_TREND_CALC = 2;
  const TREND_PERCENTAGE_THRESHOLD = 0.1; // 10%
  const MIN_ABSOLUTE_TREND_THRESHOLD = 0.01;

  const mid = Math.floor(windowSamples.length / 2);
  if (mid < MIN_SAMPLES_FOR_TREND_CALC) return { current, trend: "stable", samples: windowSamples.length };

  const firstHalf = windowSamples.slice(0, mid);
  const secondHalf = windowSamples.slice(mid);
  const firstAvg = firstHalf.reduce((sum, s) => sum + s.value, 0) / firstHalf.length;
  const secondAvg = secondHalf.reduce((sum, s) => sum + s.value, 0) / secondHalf.length;

  const delta = secondAvg - firstAvg;
  const threshold = Math.max(Math.abs(firstAvg) * TREND_PERCENTAGE_THRESHOLD, MIN_ABSOLUTE_TREND_THRESHOLD);

  let trend: "rising" | "falling" | "stable" = "stable";
  if (delta > threshold) trend = "rising";
  else if (delta < -threshold) trend = "falling";

  return { current, trend, samples: windowSamples.length };
}

// ─── Alert System ─────────────────────────────────────────────────────────────

function checkThreshold(type: MetricType, metric: { current: number; trend: string; samples: number }): MonitorAlert | null {
  if (metric.samples < config.minSamplesForAlert) return null;

  const thresholdKey = type as keyof typeof config.thresholds;
  const threshold = config.thresholds[thresholdKey];
  if (threshold === undefined) return null;

  if (metric.current <= threshold) {
    // Resolve any active alerts for this type
    for (const alert of alerts) {
      if (alert.type === type && !alert.resolvedAt) {
        alert.resolvedAt = Date.now();
      }
    }
    return null;
  }

  // Check if there's already an active (unresolved) alert for this type
  const existingActive = alerts.find(a => a.type === type && !a.resolvedAt);
  if (existingActive) return null; // Don't duplicate

  const severity = metric.current > threshold * 2 ? "critical"
    : metric.current > threshold * 1.5 ? "warning"
    : "info";

  const alert: MonitorAlert = {
    id: randomUUID(),
    type,
    severity,
    message: `${type} is at ${(metric.current * (type === "response_latency" ? 1 : 100)).toFixed(1)}${type === "response_latency" ? "ms" : "%"}, exceeding threshold of ${(threshold * (type === "response_latency" ? 1 : 100)).toFixed(1)}${type === "response_latency" ? "ms" : "%"}. Trend: ${metric.trend}.`,
    currentValue: metric.current,
    threshold,
    trend: metric.trend as "rising" | "falling" | "stable",
    triggered: false,
    createdAt: Date.now(),
  };

  alerts.push(alert);
  if (alerts.length > MAX_ALERTS) alerts.splice(0, alerts.length - MAX_ALERTS);

  return alert;
}

// ─── Auto-Improvement Trigger ─────────────────────────────────────────────────

async function maybeAutoTrigger(alert: MonitorAlert): Promise<boolean> {
  if (!config.autoTriggerImprovement) return false;
  if (alert.severity === "info") return false;

  const now = Date.now();
  if (now - lastImprovementTrigger < config.cooldownMs) return false;

  // Mark the alert as triggered
  alert.triggered = true;
  lastImprovementTrigger = now;
  improvementsTriggered++;

  // v5.23: Actually trigger the self-improvement pipeline
  // v5.50: Capture outcomes and log to memory for closed-loop feedback
  try {
    const { autoApplyHighConfidence } = await import("./selfImprove.js");
    const applyResults = await autoApplyHighConfidence();

    // v5.50: Record the monitoring trigger and its outcome in persistent memory
    try {
      const { storeMemory } = await import("./memory.js");
      const applied = applyResults.filter(r => r.applied);
      const failed = applyResults.filter(r => !r.applied);
      const memContent = [
        `[Monitor->AutoFix] Triggered by: ${alert.type} (${alert.severity})`,
        `Alert: ${alert.message}`,
        `Proposals applied: ${applied.length} | Failed: ${failed.length}`,
        applied.length > 0 ? `Applied: ${applied.map(r => r.title).join("; ")}` : "",
        failed.length > 0 ? `Failed: ${failed.map(r => r.message).join("; ")}` : "",
        `TriggeredAt: ${new Date().toISOString()}`,
      ].filter(Boolean).join("\n");
      storeMemory(memContent, "project", ["monitor", "auto-fix", alert.type]);
    } catch (memErr) { console.warn(`[SelfMonitor] Failed to store memory: ${(memErr as Error).message}`); }

    console.log(`[Monitor->Improve] Auto-trigger complete: ${applyResults.filter(r => r.applied).length} applied, ${applyResults.filter(r => !r.applied).length} skipped`);
  } catch (err) {
    // Non-fatal — log and continue monitoring
    console.error("[Monitor->Improve] Auto-trigger failed:", err instanceof Error ? err.message : String(err));
  }
  return true;
}

// ─── Health Check Loop ────────────────────────────────────────────────────────

async function runHealthCheck(): Promise<void> {
  if (!config.enabled) return;
  lastCheckTime = Date.now();

  const metricTypes: MetricType[] = ["error_rate", "response_latency", "truncation_rate", "tool_failure_rate", "self_modify_success", "self_modify_rollback", "proposal_quality"];

  for (const type of metricTypes) {
    const metric = calculateMetric(type);
    const alert = checkThreshold(type, metric);
    if (alert) {
      await maybeAutoTrigger(alert);
    }
  }
}

// ─── Public API ───────────────────────────────────────────────────────────────

export function getMonitorConfig(): MonitorConfig {
  return { ...config };
}

export function setMonitorConfig(updates: Partial<MonitorConfig>): MonitorConfig {
  config = { ...config, ...updates };
  if (updates.thresholds) {
    config.thresholds = { ...defaultConfig.thresholds, ...updates.thresholds };
  }

  // Restart interval if changed
  if (updates.checkIntervalMs !== undefined || updates.enabled !== undefined) {
    stopMonitor();
    if (config.enabled) startMonitor();
  }

  return config;
}

export function getHealthReport(): HealthReport {
  const metricTypes: MetricType[] = ["error_rate", "response_latency", "truncation_rate", "tool_failure_rate", "memory_usage", "user_satisfaction", "self_modify_success", "self_modify_rollback", "proposal_quality"];
  const metrics: Record<string, { current: number; trend: "rising" | "falling" | "stable"; samples: number }> = {};

  for (const type of metricTypes) {
    metrics[type] = calculateMetric(type);
  }

  const activeAlerts = alerts.filter(a => !a.resolvedAt);
  const hasCritical = activeAlerts.some(a => a.severity === "critical");
  const hasWarning = activeAlerts.some(a => a.severity === "warning");

  return {
    status: hasCritical ? "critical" : hasWarning ? "degraded" : "healthy",
    metrics: metrics as any,
    activeAlerts,
    lastCheck: lastCheckTime,
    uptime: Date.now() - monitorStartTime,
    totalSamples: samples.length,
    improvementsTriggered,
  };
}

export function getAlerts(includeResolved: boolean = false): MonitorAlert[] {
  if (includeResolved) return [...alerts];
  return alerts.filter(a => !a.resolvedAt);
}

export function resolveAlert(alertId: string): boolean {
  const alert = alerts.find(a => a.id === alertId);
  if (!alert || alert.resolvedAt) return false;
  alert.resolvedAt = Date.now();
  return true;
}

export function getMetricHistory(type: MetricType, limit: number = 100): MetricSample[] {
  return samples.filter(s => s.type === type).slice(-limit);
}

/**
 * Get a summary for injection into the system prompt.
 */
export function getMonitorSummary(): string {
  const report = getHealthReport();
  if (report.totalSamples === 0) return "";

  const lines = [`## System Health: ${report.status.toUpperCase()}`];

  if (report.activeAlerts.length > 0) {
    lines.push(`⚠ ${report.activeAlerts.length} active alert(s):`);
    for (const alert of report.activeAlerts) {
      lines.push(`  - [${alert.severity}] ${alert.message}`);
    }
  }

  const errMetric = report.metrics.error_rate;
  if (errMetric && errMetric.samples > 0) {
    lines.push(`Error rate: ${(errMetric.current * 100).toFixed(1)}% (${errMetric.trend})`);
  }

  return lines.join("\n");
}

// ─── Lifecycle ────────────────────────────────────────────────────────────────

export function startMonitor(): void {
  if (monitorInterval) return;

  // v5.32: Load persisted metrics from previous session
  loadPersistedMetrics();

  monitorStartTime = Date.now();
  monitorInterval = setInterval(() => {
    runHealthCheck().catch((err) => console.warn(`[SelfMonitor] Health check error: ${(err as Error).message}`));
  }, config.checkIntervalMs);

  // v5.32: Start periodic persistence
  persistInterval = setInterval(() => {
    persistMetrics();
  }, PERSIST_INTERVAL_MS);

  // Run an immediate check
  runHealthCheck().catch((err) => console.warn(`[SelfMonitor] Initial health check error: ${(err as Error).message}`));
}

export function stopMonitor(): void {
  if (monitorInterval) {
    clearInterval(monitorInterval);
    monitorInterval = null;
  }
  if (persistInterval) {
    clearInterval(persistInterval);
    persistInterval = null;
  }
  // v5.32: Persist metrics on shutdown
  persistMetrics();
}

export function isMonitorRunning(): boolean {
  return monitorInterval !== null;
}

/**
 * Reset all monitoring data. Useful for testing.
 */
export function resetMonitor(): void {
  samples.length = 0;
  alerts.length = 0;
  improvementsTriggered = 0;
  lastImprovementTrigger = 0;
  lastCheckTime = 0;
  monitorStartTime = Date.now();
}

// ═══════════════════════════════════════════════════════════════════════════
// v5.7 Enhancement: Adaptive Per-Provider Threshold Learning
// ═══════════════════════════════════════════════════════════════════════════

export type ProviderBaseline = {
  providerId: string;
  avgLatency: number;
  p95Latency: number;
  avgErrorRate: number;
  avgTokensPerSec: number;
  sampleCount: number;
  lastUpdated: number;
  thresholds: {
    maxLatency: number;
    maxErrorRate: number;
    minTokensPerSec: number;
  };
};

export type ProviderSample = {
  providerId: string;
  latency: number;
  success: boolean;
  tokensPerSec?: number;
  timestamp: number;
};

export type AdaptiveConfig = {
  enabled: boolean;
  learningWindow: number;
  minSamplesForBaseline: number;
  latencyMargin: number;
  errorRateMargin: number;
  throughputMargin: number;
  recalcInterval: number;
};

const providerSamples: ProviderSample[] = [];
const providerBaselines = new Map<string, ProviderBaseline>();
let adaptiveConfig: AdaptiveConfig = {
  enabled: true,
  learningWindow: 60 * 60 * 1000,
  minSamplesForBaseline: 10,
  latencyMargin: 1.5,
  errorRateMargin: 2.0,
  throughputMargin: 0.6,
  recalcInterval: 5 * 60 * 1000,
};
let lastBaselineCalc = 0;

export function recordProviderSample(sample: ProviderSample): void {
  providerSamples.push(sample);
  const cutoff = Date.now() - adaptiveConfig.learningWindow * 2;
  while (providerSamples.length > 0 && providerSamples[0].timestamp < cutoff) {
    providerSamples.shift();
  }
  if (providerSamples.length > 10_000) {
    providerSamples.splice(0, providerSamples.length - 10_000);
  }
}

export function recalculateBaselines(): Map<string, ProviderBaseline> {
  if (!adaptiveConfig.enabled) return providerBaselines;
  const now = Date.now();
  const windowStart = now - adaptiveConfig.learningWindow;
  const byProvider = new Map<string, ProviderSample[]>();
  for (const sample of providerSamples) {
    if (sample.timestamp < windowStart) continue;
    const existing = byProvider.get(sample.providerId) || [];
    existing.push(sample);
    byProvider.set(sample.providerId, existing);
  }
  for (const [providerId, pSamples] of Array.from(byProvider.entries())) {
    if (pSamples.length < adaptiveConfig.minSamplesForBaseline) continue;
    const latencies = pSamples.filter(s => s.success).map(s => s.latency).sort((a, b) => a - b);
    const errorCount = pSamples.filter(s => !s.success).length;
    const tokensPerSec = pSamples.filter(s => s.tokensPerSec != null).map(s => s.tokensPerSec!);
    if (latencies.length === 0) continue;
    const avgLatency = latencies.reduce((a, b) => a + b, 0) / latencies.length;
    const p95Index = Math.floor(latencies.length * 0.95);
    const p95Latency = latencies[p95Index] || latencies[latencies.length - 1];
    const avgErrorRate = errorCount / pSamples.length;
    const avgTps = tokensPerSec.length > 0 ? tokensPerSec.reduce((a, b) => a + b, 0) / tokensPerSec.length : 0;
    providerBaselines.set(providerId, {
      providerId,
      avgLatency: Math.round(avgLatency),
      p95Latency: Math.round(p95Latency),
      avgErrorRate: Math.round(avgErrorRate * 1000) / 1000,
      avgTokensPerSec: Math.round(avgTps * 10) / 10,
      sampleCount: pSamples.length,
      lastUpdated: now,
      thresholds: {
        maxLatency: Math.round(p95Latency * adaptiveConfig.latencyMargin),
        maxErrorRate: Math.max(0.05, avgErrorRate * adaptiveConfig.errorRateMargin),
        minTokensPerSec: avgTps > 0 ? Math.round(avgTps * adaptiveConfig.throughputMargin * 10) / 10 : 0,
      },
    });
  }
  lastBaselineCalc = now;
  return providerBaselines;
}

export function getAdaptiveThresholds(providerId: string): ProviderBaseline["thresholds"] {
  if (Date.now() - lastBaselineCalc > adaptiveConfig.recalcInterval) recalculateBaselines();
  const baseline = providerBaselines.get(providerId);
  if (baseline) return baseline.thresholds;
  return { maxLatency: 30_000, maxErrorRate: 0.15, minTokensPerSec: 5 };
}

export function isProviderDegraded(providerId: string): { degraded: boolean; reasons: string[]; baseline?: ProviderBaseline } {
  const thresholds = getAdaptiveThresholds(providerId);
  const baseline = providerBaselines.get(providerId);
  const reasons: string[] = [];
  const recentCutoff = Date.now() - 2 * 60 * 1000;
  const recent = providerSamples.filter(s => s.providerId === providerId && s.timestamp > recentCutoff);
  if (recent.length < 3) return { degraded: false, reasons: [], baseline };
  const recentLatencies = recent.filter(s => s.success).map(s => s.latency);
  if (recentLatencies.length > 0) {
    const avgRecent = recentLatencies.reduce((a, b) => a + b, 0) / recentLatencies.length;
    if (avgRecent > thresholds.maxLatency) reasons.push(`Latency ${Math.round(avgRecent)}ms exceeds threshold ${thresholds.maxLatency}ms`);
  }
  const recentErrors = recent.filter(s => !s.success).length;
  const recentErrorRate = recentErrors / recent.length;
  if (recentErrorRate > thresholds.maxErrorRate) reasons.push(`Error rate ${(recentErrorRate * 100).toFixed(1)}% exceeds threshold ${(thresholds.maxErrorRate * 100).toFixed(1)}%`);
  const recentTps = recent.filter(s => s.tokensPerSec != null).map(s => s.tokensPerSec!);
  if (recentTps.length > 0 && thresholds.minTokensPerSec > 0) {
    const avgTps = recentTps.reduce((a, b) => a + b, 0) / recentTps.length;
    if (avgTps < thresholds.minTokensPerSec) reasons.push(`Throughput ${avgTps.toFixed(1)} tok/s below threshold ${thresholds.minTokensPerSec} tok/s`);
  }
  return { degraded: reasons.length > 0, reasons, baseline };
}

export function getAllBaselines(): ProviderBaseline[] {
  if (Date.now() - lastBaselineCalc > adaptiveConfig.recalcInterval) recalculateBaselines();
  return Array.from(providerBaselines.values());
}

export function getAdaptiveConfig(): AdaptiveConfig {
  return { ...adaptiveConfig };
}

export function setAdaptiveConfig(updates: Partial<AdaptiveConfig>): AdaptiveConfig {
  adaptiveConfig = { ...adaptiveConfig, ...updates };
  return { ...adaptiveConfig };
}

export function getAdaptiveStats(): { totalSamples: number; providersTracked: number; degradedProviders: string[]; oldestSample: number; newestSample: number } {
  const degraded: string[] = [];
  for (const [id] of Array.from(providerBaselines.entries())) {
    if (isProviderDegraded(id).degraded) degraded.push(id);
  }
  return {
    totalSamples: providerSamples.length,
    providersTracked: providerBaselines.size,
    degradedProviders: degraded,
    oldestSample: providerSamples.length > 0 ? providerSamples[0].timestamp : 0,
    newestSample: providerSamples.length > 0 ? providerSamples[providerSamples.length - 1].timestamp : 0,
  };
}

// v5.26: Alias for diagnostics endpoint
export const getMonitorStats = getHealthReport;

/**
 * Andromeda v5.27 — Autonomous Goal Suggestion Engine
 * v6.31: Replaced isRunning boolean guard with withAutoGoalLock() distributed lock.
 *
 * Analyzes system logs, error patterns, and performance metrics
 * to proactively suggest improvement goals without user intervention.
 *
 * Integrates with:
 * - selfMonitor.ts (metrics)
 * - selfKnowledgeBase.ts (known issues)
 * - recursiveGoals.ts (goal creation)
 * - redisLock.ts (distributed concurrency control)
 */

import { withAutoGoalLock } from "./redisLock.js";

// ── Types ────────────────────────────────────────────────────────────────────

interface GoalSuggestion {
  id: string;
  title: string;
  description: string;
  priority: "critical" | "high" | "medium" | "low";
  source: "error_pattern" | "performance_drop" | "knowledge_gap" | "recurring_issue";
  confidence: number; // 0-1
  suggestedAt: number;
  autoExecute: boolean;
}

interface SuggesterConfig {
  enabled: boolean;
  intervalMs: number;
  maxSuggestionsPerCycle: number;
  autoExecuteThreshold: number; // confidence threshold for auto-execution
}

// ── State ────────────────────────────────────────────────────────────────────

const DEFAULT_CONFIG: SuggesterConfig = {
  enabled: true, // v5.30: Enabled by default
  intervalMs: 30 * 60 * 1000, // Every 30 minutes
  maxSuggestionsPerCycle: 3,
  autoExecuteThreshold: 0.9,
};

let config: SuggesterConfig = { ...DEFAULT_CONFIG };
let suggesterTimer: ReturnType<typeof setInterval> | null = null;
// v6.31: isRunning replaced by withAutoGoalLock() distributed lock
let _timerActive = false;
const suggestions: GoalSuggestion[] = [];
const MAX_SUGGESTIONS = 100;

// ── Analysis Functions ───────────────────────────────────────────────────────

async function analyzeErrorPatterns(): Promise<GoalSuggestion[]> {
  return handleAnalysisError(
    async () => {
      const results: GoalSuggestion[] = [];
      const { getOpenIssues } = await import("./selfKnowledgeBase");
      const openIssues = getOpenIssues();

      // Group by module
      const byModule: Record<string, number> = {};
      for (const issue of openIssues) {
        const modules = issue.affectedModules || ["unknown"];
        for (const mod of modules) {
          byModule[mod] = (byModule[mod] || 0) + 1;
        }
      }

      // Suggest goals for modules with multiple open issues
      for (const [module, count] of Object.entries(byModule)) {
        if (count >= 3) {
          results.push({
            id: `goal_err_${module}_${Date.now()}`,
            title: `Reduce error rate in ${module}`,
            description: `Module "${module}" has ${count} open issues. Investigate root causes and apply fixes.`,
            priority: count >= 5 ? "high" : "medium",
            source: "error_pattern",
            confidence: Math.min(0.95, 0.6 + count * 0.05),
            suggestedAt: Date.now(),
            autoExecute: false,
          });
        }
      }
      return results;
    },
    "analyzeErrorPatterns"
  );
}

// Helper for centralized error handling
async function handleAnalysisError<T>(fn: () => Promise<T>, functionName: string): Promise<T | []> {
  try {
    return await fn();
  } catch (err) {
    console.warn(`[AutoGoalSuggester] ${functionName} failed:`, (err as Error).message);
    return [];
  }
}

async function analyzePerformanceMetrics(): Promise<GoalSuggestion[]> {
  return handleAnalysisError(async () => {
    const results: GoalSuggestion[] = [];
    const { getHealthReport } = await import("./selfMonitor");
    const status = getHealthReport();
    if (status && status.metrics) {
      // Check for degrading metrics
      for (const [key, metric] of Object.entries(status.metrics) as [string, any][]) {
        if (metric && metric.trend === "degrading" && metric.samples > 5) {
          results.push({
            id: `goal_perf_${key}_${Date.now()}`,
            title: `Improve ${key.replace(/_/g, " ")}`,
            description: `Metric "${key}" is trending downward (current: ${metric.current}). Investigate and optimize.`,
            priority: metric.current < 0.5 ? "high" : "medium",
            source: "performance_drop",
            confidence: 0.7,
            suggestedAt: Date.now(),
            autoExecute: false,
          });
        }
      }
    }
    return results;
  }, "analyzePerformanceMetrics");
}

async function analyzeRecurringIssues(): Promise<GoalSuggestion[]> {
  return handleAnalysisError(async () => {
    const results: GoalSuggestion[] = [];
    const { getCrossSessionInsights } = await import("./selfKnowledgeBase");
    const insights = getCrossSessionInsights();
    if (insights.totalAttempts > 5 && insights.successRate < 0.5) {
      results.push({
        id: `goal_recurring_${Date.now()}`,
        title: "Improve self-modification success rate",
        description: `Self-modification success rate is ${(insights.successRate * 100).toFixed(0)}% (${insights.totalAttempts} attempts). Top anti-patterns: ${insights.topAntiPatterns.slice(0, 2).join("; ")}`,
        priority: "high",
        source: "recurring_issue",
        confidence: 0.85,
        suggestedAt: Date.now(),
        autoExecute: false,
      });
    }
    return results;
  }, "analyzeRecurringIssues");
}

// ── Core Suggestion Cycle ────────────────────────────────────────────────────

async function runSuggestionCycle(): Promise<GoalSuggestion[]> {
  const newSuggestions: GoalSuggestion[] = [];

  const [errorGoals, perfGoals, recurringGoals] = await Promise.all([
    analyzeErrorPatterns(),
    analyzePerformanceMetrics(),
    analyzeRecurringIssues(),
  ]);

  newSuggestions.push(...errorGoals, ...perfGoals, ...recurringGoals);

  // Deduplicate against existing suggestions
  const existingTitles = new Set(suggestions.map(s => s.title));
  const unique = newSuggestions.filter(s => !existingTitles.has(s.title));

  // Limit per cycle
  const toAdd = unique.slice(0, config.maxSuggestionsPerCycle);
  suggestions.push(...toAdd);
  if (suggestions.length > MAX_SUGGESTIONS) {
    suggestions.splice(0, suggestions.length - MAX_SUGGESTIONS);
  }

  // Auto-execute high-confidence goals
  for (const suggestion of toAdd) {
    if (suggestion.confidence >= config.autoExecuteThreshold && suggestion.autoExecute) {
      try {
        const { createGoal } = await import("./recursiveGoals") as any;
        if (createGoal) {
          createGoal({
            title: suggestion.title,
            description: suggestion.description,
            priority: suggestion.priority,
            source: "auto_suggester",
          });
          console.log(`[AutoGoalSuggester] Auto-created goal: ${suggestion.title}`);
        }
      } catch (err) { console.warn(`[AutoGoalSuggester] Failed to create goal: ${(err as Error).message}`); }
    }
  }

  if (toAdd.length > 0) {
    console.log(`[AutoGoalSuggester] Generated ${toAdd.length} new suggestions.`);
  }
  return toAdd;
}

// ── Public API ───────────────────────────────────────────────────────────────

export function startAutoGoalSuggester(overrides?: Partial<SuggesterConfig>): void {
  if (overrides) config = { ...config, ...overrides };
  if (!config.enabled) {
    console.log("[AutoGoalSuggester] Disabled. Set enabled: true to activate.");
    return;
  }
  if (_timerActive) return;

  // v6.31: Each interval tick acquires the distributed lock before running
  _timerActive = true;
  suggesterTimer = setInterval(() => {
    withAutoGoalLock(() => runSuggestionCycle()).catch(err =>
      console.warn("[AutoGoalSuggester] Cycle skipped (lock busy or error):", (err as Error).message)
    );
  }, config.intervalMs);
  console.log(`[AutoGoalSuggester] Started. Interval: ${config.intervalMs / 1000 / 60}min`);
}

export function stopAutoGoalSuggester(): void {
  if (suggesterTimer) clearInterval(suggesterTimer);
  suggesterTimer = null;
  _timerActive = false;
  // v6.31: No isRunning flag to clear — lock releases automatically
}

export function getSuggestions(limit = 20): GoalSuggestion[] {
  return suggestions.slice(-limit);
}

export async function triggerSuggestionCycle(): Promise<GoalSuggestion[]> {
  // v6.31: Acquire lock for manual trigger too
  const result = await withAutoGoalLock(() => runSuggestionCycle());
  return result.result ?? [];
}

export function getSuggesterStats() {
  return {
    enabled: config.enabled,
    running: _timerActive,
    totalSuggestions: suggestions.length,
    intervalMs: config.intervalMs,
  };
}

/**
 * autonomousGoalGenerator.ts — v5.33
 *
 * Autonomous Goal Generation Module.
 *
 * Enables Andromeda to identify its own weaknesses and create improvement
 * goals WITHOUT human prompting. This is the key module that transforms
 * Andromeda from a tool into an agent.
 *
 * Goal sources:
 * 1. Self-model capability gaps
 * 2. Error log patterns
 * 3. Performance metric degradation
 * 4. Test coverage gaps
 * 5. Dependency health
 * 6. Cross-session learning patterns
 *
 * Safety:
 * - Goals are generated but NOT auto-applied by default
 * - Each goal has a confidence score
 * - Goals targeting protected modules are blocked (via recursiveGoals guard)
 * - Maximum 5 auto-generated goals per cycle
 */

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

// ─── Types ─────────────────────────────────────────────────────────────────────

export interface GeneratedGoal {
  id: string;
  title: string;
  description: string;
  source: "capability_gap" | "error_pattern" | "performance" | "coverage" | "dependency" | "learning";
  priority: number;       // 1-10
  confidence: number;     // 0-1
  estimatedEffort: "low" | "medium" | "high";
  targetFiles: string[];
  autoGenerated: true;
  createdAt: number;
  status: "proposed" | "approved" | "in_progress" | "completed" | "rejected";
  rationale: string;
}

export interface GoalGenerationResult {
  goals: GeneratedGoal[];
  analysisTime: number;
  sourcesAnalyzed: string[];
  skipped: string[];
}

// ─── Storage ───────────────────────────────────────────────────────────────────

const MAX_GOALS_PER_CYCLE = 5;
const MAX_STORED_GOALS = 50;
let generatedGoals: GeneratedGoal[] = [];
let lastGenerationTime = 0;
const COOLDOWN_MS = 10 * 60 * 1000; // 10 minutes between generations

function getGoalsPath(): string {
  const serverDir = path.dirname(fileURLToPath(import.meta.url));
  const workspaceDir = path.resolve(serverDir, "..", "workspace");
  if (!fs.existsSync(workspaceDir)) fs.mkdirSync(workspaceDir, { recursive: true });
  return path.join(workspaceDir, ".andromeda_auto_goals.json");
}

function loadGoals(): void {
  try {
    const goalsPath = getGoalsPath();
    if (fs.existsSync(goalsPath)) {
      generatedGoals = JSON.parse(fs.readFileSync(goalsPath, "utf-8"));
    }
  } catch (err) {
    console.warn(`[AutoGoalGen] Failed to load goals: ${(err as Error).message}`);
  }
}

function saveGoals(): void {
  try {
    // Keep only the most recent goals
    if (generatedGoals.length > MAX_STORED_GOALS) {
      generatedGoals = generatedGoals.slice(-MAX_STORED_GOALS);
    }
    const goalsPath = getGoalsPath();
    fs.writeFileSync(goalsPath, JSON.stringify(generatedGoals, null, 2));
  } catch (err) {
    console.warn(`[AutoGoalGen] Failed to save goals: ${(err as Error).message}`);
  }
}

function generateId(): string {
  return `agoal_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

function createGoal(params: {
  title: string;
  description: string;
  source: GeneratedGoal['source'];
  priority: number;
  confidence: number;
  estimatedEffort: GeneratedGoal['estimatedEffort'];
  targetFiles?: string[];
  rationale: string;
}): GeneratedGoal {
  return {
    id: generateId(),
    title: params.title,
    description: params.description,
    source: params.source,
    priority: params.priority,
    confidence: params.confidence,
    estimatedEffort: params.estimatedEffort,
    targetFiles: params.targetFiles || [],
    autoGenerated: true,
    createdAt: Date.now(),
    status: 'proposed',
    rationale: params.rationale,
  };
}

// ─── Goal Source Analyzers ─────────────────────────────────────────────────────

/**
 * Analyze self-model for capability gaps.
 */
async function analyzeCapabilityGaps(): Promise<GeneratedGoal[]> {
  const goals: GeneratedGoal[] = [];

  try {
    const { getSelfModel } = await import("./selfModel");
    const model = getSelfModel();

    if (model && model.capabilities) {
      const caps = Array.isArray(model.capabilities) ? model.capabilities : Object.values(model.capabilities);
      for (const cap of caps) {
        const c = cap as any;
        if (c.enabled === false || c.status === "degraded" || c.status === "disabled") {
          goals.push(createGoal({
            title: `Enable/fix ${c.name || "unknown"} capability`,
            description: `Capability '${c.name || "unknown"}' is ${c.status || "disabled"}. Investigate and restore.`,
            source: "capability_gap",
            priority: 8,
            confidence: 0.9,
            estimatedEffort: "medium",
            targetFiles: c.module ? [`server/${c.module}.ts`] : [],
            rationale: `Self-model reports capability as ${c.status || "disabled"}`,
          }));
        }
      }
    }
  } catch (err) {
    console.warn(`[AutoGoalGen] analyzeCapabilityGaps: selfModel not available: ${(err as Error).message}`);
  }

  return goals;
}

/**
 * Analyze error patterns from selfMonitor.
 */
async function analyzeErrorPatterns(): Promise<GeneratedGoal[]> {
  const goals: GeneratedGoal[] = [];

  try {
    const { getHealthReport } = await import("./selfMonitor");
    const report = getHealthReport();

    if (report && report.metrics) {
      const metrics = report.metrics as Record<string, any>;

      // High error rate
      if (metrics.error_rate && metrics.error_rate.current > 0.1) {
        goals.push(createGoal({
          title: "Reduce error rate below 10%",
          description: `Current error rate is ${(metrics.error_rate.current * 100).toFixed(1)}%. Analyze recent errors and implement fixes.`,
          source: "error_pattern",
          priority: 9,
          confidence: 0.85,
          estimatedEffort: "medium",
          rationale: `Error rate ${(metrics.error_rate.current * 100).toFixed(1)}% exceeds 10% threshold`,
        }));
      }

      // High truncation rate
      if (metrics.truncation_rate && metrics.truncation_rate.current > 0.15) {
        goals.push(createGoal({
          title: "Reduce truncation rate below 15%",
          description: `Current truncation rate is ${(metrics.truncation_rate.current * 100).toFixed(1)}%. Optimize context management and token budgets.`,
          source: "error_pattern",
          priority: 9,
          confidence: 0.9,
          estimatedEffort: "high",
          targetFiles: ["server/tieredContextManager.ts", "server/tokenBudgetManager.ts"],
          rationale: `Truncation rate ${(metrics.truncation_rate.current * 100).toFixed(1)}% exceeds 15% threshold`,
        }));
      }

      // High latency
      if (metrics.response_latency && metrics.response_latency.current > 20000) {
        goals.push(createGoal({
          title: "Reduce response latency below 20s",
          description: `Average response latency is ${(metrics.response_latency.current / 1000).toFixed(1)}s. Optimize LLM calls and caching.`,
          source: "performance",
          priority: 7,
          confidence: 0.8,
          estimatedEffort: "high",
          targetFiles: ["server/ai.ts", "server/_core/llm.ts"],
          rationale: `Latency ${(metrics.response_latency.current / 1000).toFixed(1)}s exceeds 20s threshold`,
        }));
      }

      // High tool failure rate
      if (metrics.tool_failure_rate && metrics.tool_failure_rate.current > 0.15) {
        goals.push(createGoal({
          title: "Reduce tool failure rate below 15%",
          description: `Tool failure rate is ${(metrics.tool_failure_rate.current * 100).toFixed(1)}%. Investigate failing tools and add error handling.`,
          source: "error_pattern",
          priority: 8,
          confidence: 0.85,
          estimatedEffort: "medium",
          rationale: `Tool failure rate ${(metrics.tool_failure_rate.current * 100).toFixed(1)}% exceeds 15% threshold`,
        }));
      }
    }
  } catch {
    // selfMonitor not available
  }

  return goals;
}

/**
 * Analyze cross-session learnings for improvement opportunities.
 */
async function analyzeLearningPatterns(): Promise<GeneratedGoal[]> {
  const goals: GeneratedGoal[] = [];

  try {
    const { queryUnifiedKnowledge } = await import("./unifiedKnowledge");
    const errorLearnings = await queryUnifiedKnowledge({
      query: "error fix improvement bug",
      sources: ["systemMemory", "selfKnowledgeBase"],
      limit: 10,
      minRelevance: 0.3,
    });

    // If we have many error-related learnings, suggest a systematic review
    if (errorLearnings.entries.length >= 5) {
      goals.push({
        id: generateId(),
        title: "Systematic review of recurring error patterns",
        description: `Found ${errorLearnings.entries.length} error-related learnings across sessions. A systematic review could identify root causes.`,
        source: "learning",
        priority: 6,
        confidence: 0.7,
        estimatedEffort: "medium",
        targetFiles: [],
        autoGenerated: true,
        createdAt: Date.now(),
        status: "proposed",
        rationale: `${errorLearnings.entries.length} error-related learnings suggest recurring issues`,
      });
    }
  } catch {
    // unifiedKnowledge not available
  }

  return goals;
}

// ─── Main Generation Function ──────────────────────────────────────────────────

/**
 * Generate improvement goals autonomously.
 * Analyzes multiple sources and creates prioritized goals.
 */
export async function generateImprovementGoals(): Promise<GoalGenerationResult> {
  const startTime = Date.now();

  // Cooldown check
  if (Date.now() - lastGenerationTime < COOLDOWN_MS) {
    return {
      goals: [],
      analysisTime: 0,
      sourcesAnalyzed: [],
      skipped: ["Cooldown active"],
    };
  }

  loadGoals();
  lastGenerationTime = Date.now();

  const sourcesAnalyzed: string[] = [];
  const skipped: string[] = [];
  const newGoals: GeneratedGoal[] = [];

  // ── 1. Capability gaps ──
  try {
    const capGoals = await analyzeCapabilityGaps();
    newGoals.push(...capGoals);
    sourcesAnalyzed.push("capability_gaps");
  } catch {
    skipped.push("capability_gaps");
  }

  // ── 2. Error patterns ──
  try {
    const errorGoals = await analyzeErrorPatterns();
    newGoals.push(...errorGoals);
    sourcesAnalyzed.push("error_patterns");
  } catch {
    skipped.push("error_patterns");
  }

  // ── 3. Learning patterns ──
  try {
    const learningGoals = await analyzeLearningPatterns();
    newGoals.push(...learningGoals);
    sourcesAnalyzed.push("learning_patterns");
  } catch {
    skipped.push("learning_patterns");
  }

  // ── Deduplicate against existing goals ──
  const existingTitles = new Set(generatedGoals.map(g => g.title.toLowerCase()));
  const uniqueGoals = newGoals.filter(g => !existingTitles.has(g.title.toLowerCase()));

  // ── Sort by priority * confidence ──
  uniqueGoals.sort((a, b) => (b.priority * b.confidence) - (a.priority * a.confidence));

  // ── Limit ──
  const finalGoals = uniqueGoals.slice(0, MAX_GOALS_PER_CYCLE);

  // ── Store ──
  generatedGoals.push(...finalGoals);
  saveGoals();

  // ── Register with recursiveGoals if available ──
  try {
    const { createMetaGoal } = await import("./recursiveGoals");
    for (const goal of finalGoals) {
      createMetaGoal({
        type: "self_improvement",
        title: goal.title,
        description: goal.description,
        rationale: goal.rationale,
        priority: goal.priority,
        recursive: false,
        subGoals: goal.targetFiles.map(f => ({
          title: `Investigate ${f}`,
          description: `Analyze and fix issues in ${f}`,
          targetFile: f,
        })),
      });
    }
  } catch {
    // recursiveGoals not available
  }

  return {
    goals: finalGoals,
    analysisTime: Date.now() - startTime,
    sourcesAnalyzed,
    skipped,
  };
}

// ─── Goal Management ───────────────────────────────────────────────────────────

export function getGeneratedGoals(): GeneratedGoal[] {
  if (generatedGoals.length === 0) loadGoals();
  return [...generatedGoals];
}

export function approveGoal(goalId: string): boolean {
  const goal = generatedGoals.find(g => g.id === goalId);
  if (goal && goal.status === "proposed") {
    goal.status = "approved";
    saveGoals();
    return true;
  }
  return false;
}

export function rejectGoal(goalId: string): boolean {
  const goal = generatedGoals.find(g => g.id === goalId);
  if (goal && goal.status === "proposed") {
    goal.status = "rejected";
    saveGoals();
    return true;
  }
  return false;
}

// ─── Diagnostics ───────────────────────────────────────────────────────────────

export function getGoalGeneratorStats(): {
  totalGenerated: number;
  proposed: number;
  approved: number;
  completed: number;
  rejected: number;
  lastGenerationTime: number;
} {
  if (generatedGoals.length === 0) loadGoals();
  return {
    totalGenerated: generatedGoals.length,
    proposed: generatedGoals.filter(g => g.status === "proposed").length,
    approved: generatedGoals.filter(g => g.status === "approved").length,
    completed: generatedGoals.filter(g => g.status === "completed").length,
    rejected: generatedGoals.filter(g => g.status === "rejected").length,
    lastGenerationTime,
  };
}

/**
 * Andromeda v5.28 — Autonomy Orchestrator
 *
 * The central coordinator that ties all autonomous subsystems together.
 * Runs a priority-ordered cycle:
 *   1. Health check → trigger healing if degraded
 *   2. Goal execution → process next pending goal
 *   3. Performance optimization → improve worst-performing module
 *   4. Self-improvement → analyze random module for enhancements
 *   5. Memory consolidation → compact if near capacity
 *   6. Self-model update → refresh meta-cognitive state
 *
 * This is what makes Andromeda truly autonomous — without it, modules
 * exist independently but don't coordinate.
 */
import { createLogger } from "./logger.js";
import { withOrchestratorLock } from "./redisLock.js";
const log = createLogger("autonomyOrchestrator");

// ── Types ───────────────────────────────────────────────────────────────────

interface CycleResult {
  cycleId: number;
  timestamp: number;
  duration: number;
  actions: CycleAction[];
  healthBefore: string;
  healthAfter: string;
  goalsProcessed: number;
  improvementsApplied: number;
  errors: string[];
}

interface CycleAction {
  type: "heal" | "goal" | "optimize" | "improve" | "consolidate" | "refresh";
  description: string;
  success: boolean;
  duration: number;
}

interface OrchestratorConfig {
  enabled: boolean;
  cycleIntervalMs: number;       // Default: 60_000 (1 minute)
  maxActionsPerCycle: number;    // Default: 3
  healingPriority: boolean;      // Always heal first
  autoImproveChance: number;     // 0-1, chance of self-improvement per cycle
  pauseOnCritical: boolean;      // Pause orchestrator if health is critical
  maxConsecutiveFailures: number; // Pause after N consecutive failures
}

// ── State ───────────────────────────────────────────────────────────────────

let config: OrchestratorConfig = {
  enabled: true,  // v5.30: Enabled by default — this is the core autonomy loop
  cycleIntervalMs: 120_000,  // v5.30: 2 minutes — fast enough to be responsive, slow enough to not spam
  maxActionsPerCycle: 5,     // v5.30: Increased from 3 — allow more actions per cycle
  healingPriority: true,
  autoImproveChance: 0.3,    // v5.30: Increased from 0.1 — 30% chance per cycle


  pauseOnCritical: true,
  maxConsecutiveFailures: 5,
};

// v6.31: isRunning replaced by withOrchestratorLock() distributed lock
let _orchActive = false;
let inSafeMode = false;
let cycleTimer: ReturnType<typeof setInterval> | null = null;
let totalCycles = 0;
let consecutiveFailures = 0;
let lastCycleResult: CycleResult | null = null;
const cycleHistory: CycleResult[] = [];
const MAX_HISTORY = 100;

// v5.34: Orchestrator self-monitor — tracks cycle performance and enters safe mode
// when the orchestrator itself is degraded
const cycleTimes: number[] = [];
const MAX_CYCLE_TIMES = 50;

function recordCyclePerformance(durationMs: number, success: boolean): void {
  cycleTimes.push(durationMs);
  if (cycleTimes.length > MAX_CYCLE_TIMES) cycleTimes.shift();

  // Check for degradation: if average cycle time exceeds 30s, enter safe mode
  if (cycleTimes.length >= 5) {
    const avg = cycleTimes.reduce((a, b) => a + b, 0) / cycleTimes.length;
    if (avg > 30000 && !inSafeMode) {
      console.warn(`[Orchestrator] Average cycle time ${Math.round(avg)}ms exceeds 30s threshold — entering safe mode`);
      enterSafeMode("cycle_time_degradation");
    }
  }

  // Check for repeated failures
  if (!success && consecutiveFailures >= 3 && !inSafeMode) {
    enterSafeMode("consecutive_failures");
  }
}

function enterSafeMode(reason: string): void {
  inSafeMode = true;
  console.warn(`[Orchestrator] SAFE MODE activated: ${reason}`);
  console.warn("[Orchestrator] Safe mode: only health checks and healing will run. Self-modification disabled.");
  // Record to system memory if available
  import("./systemMemory").then(m => {
    m.recordSystemLearning({
      category: "error",
      title: "Orchestrator Safe Mode",
      content: `Entered safe mode due to: ${reason}. Cycle stats: ${totalCycles} total, ${consecutiveFailures} consecutive failures.`,
      context: "orchestrator",
    });
  }).catch(() => {});
}

export function exitSafeMode(): void {
  if (!inSafeMode) return;
  inSafeMode = false;
  consecutiveFailures = 0;
  cycleTimes.length = 0;
  console.log("[Orchestrator] Safe mode DEACTIVATED — resuming full operation");
}

export function isInSafeMode(): boolean {
  return inSafeMode;
}

// ── Per-Subsystem Circuit Breaker (v6.03) ─────────────────────────────────────
// Tracks consecutive failures per subsystem. If a subsystem fails N times in a row,
// it is skipped for a cooldown period to prevent cascading errors and reduce error rate.
interface CircuitState {
  failures: number;
  lastFailure: number;
  tripped: boolean;
}
const CIRCUIT_BREAKER_THRESHOLD = 3; // Trip after 3 consecutive failures
const CIRCUIT_BREAKER_COOLDOWN_MS = 5 * 60_000; // 5 minute cooldown before retry
const subsystemCircuits = new Map<string, CircuitState>();

function isCircuitOpen(subsystem: string): boolean {
  const state = subsystemCircuits.get(subsystem);
  if (!state || !state.tripped) return false;
  // Check if cooldown has elapsed
  if (Date.now() - state.lastFailure > CIRCUIT_BREAKER_COOLDOWN_MS) {
    state.tripped = false;
    state.failures = 0;
    log.info(`Circuit breaker RESET for subsystem: ${subsystem}`);
    return false;
  }
  return true;
}

function recordSubsystemSuccess(subsystem: string): void {
  const state = subsystemCircuits.get(subsystem);
  if (state) {
    state.failures = 0;
    state.tripped = false;
  }
}

function recordSubsystemFailure(subsystem: string): void {
  let state = subsystemCircuits.get(subsystem);
  if (!state) {
    state = { failures: 0, lastFailure: 0, tripped: false };
    subsystemCircuits.set(subsystem, state);
  }
  state.failures++;
  state.lastFailure = Date.now();
  if (state.failures >= CIRCUIT_BREAKER_THRESHOLD) {
    state.tripped = true;
    log.warn(`Circuit breaker TRIPPED for subsystem: ${subsystem} (${state.failures} consecutive failures)`);
  }
}

// ── Core Cycle ──────────────────────────────────────────────────────────────

async function runCycle(): Promise<CycleResult> {
  const cycleStart = Date.now();
  totalCycles++;
  const result: CycleResult = {
    cycleId: totalCycles,
    timestamp: cycleStart,
    duration: 0,
    actions: [],
    healthBefore: "unknown",
    healthAfter: "unknown",
    goalsProcessed: 0,
    improvementsApplied: 0,
    errors: [],
  };

  let actionsRemaining = config.maxActionsPerCycle;

  try {
    // ── Step 1: Health Check ──────────────────────────────────────────────
    const healthStart = Date.now();
    let healthStatus = "healthy";
    try {
      const { getHealthReport } = await import("./selfMonitor");
      const report = getHealthReport();
      healthStatus = report.status;
      result.healthBefore = healthStatus;
    } catch (err) {
      result.errors.push(`Health check failed: ${(err as Error).message}`);
    }

    // If critical and configured to pause, stop
    if (healthStatus === "critical" && config.pauseOnCritical) {
      console.warn("[Orchestrator] Health CRITICAL — triggering emergency healing");
      try {
        const { runHealCycleOnce } = await import("./selfHeal");
        if (runHealCycleOnce) {
          await runHealCycleOnce();
          result.actions.push({
            type: "heal",
            description: "Emergency heal triggered due to critical health",
            success: true,
            duration: Date.now() - healthStart,
          });
        }
      } catch (err) {
        result.errors.push(`Emergency heal failed: ${(err as Error).message}`);
      }
      // Don't proceed with other actions during critical state
      result.duration = Date.now() - cycleStart;
      lastCycleResult = result;
      cycleHistory.push(result);
      if (cycleHistory.length > MAX_HISTORY) cycleHistory.shift();
      return result;
    }

    // ── Step 2: Healing (if degraded) ────────────────────────────────────
    if (healthStatus === "degraded" && config.healingPriority && actionsRemaining > 0 && !isCircuitOpen("heal")) {
      const healStart = Date.now();
      try {
        const { runHealCycleOnce } = await import("./selfHeal");
        if (runHealCycleOnce) {
          await runHealCycleOnce();
          result.actions.push({
            type: "heal",
            description: "Heal cycle triggered for degraded health",
            success: true,
            duration: Date.now() - healStart,
          });
          actionsRemaining--;
          recordSubsystemSuccess("heal");
        }
      } catch (err) {
        result.actions.push({
          type: "heal",
          description: `Heal failed: ${(err as Error).message}`,
          success: false,
          duration: Date.now() - healStart,
        });
        recordSubsystemFailure("heal");
      }
    }

    // ── Step 3: Goal Execution ───────────────────────────────────────────
    if (actionsRemaining > 0 && !isCircuitOpen("goals")) {
      const goalStart = Date.now();
      try {
        const { autoExecuteNextGoal } = await import("./recursiveGoals");
        const goalResult = await autoExecuteNextGoal();
        if (goalResult.executed) {
          result.goalsProcessed++;
          result.actions.push({
            type: "goal",
            description: `Executed goal: ${goalResult.goalId} — ${goalResult.result}`,
            success: true,
            duration: Date.now() - goalStart,
          });
          actionsRemaining--;
          recordSubsystemSuccess("goals");
        }
      } catch (err) {
        console.error(`[Orchestrator] Goal execution error: ${(err as Error).message}`);
        result.errors.push(`Goal execution failed: ${(err as Error).message}`);
        recordSubsystemFailure("goals");
      }
    }

    // ── Step 4: Performance Optimization ─────────────────────────────────
    if (actionsRemaining > 0) {
      const optStart = Date.now();
      try {
        const { getHealthReport } = await import("./selfMonitor");
        const report = getHealthReport();
        // Find degrading metrics
        const degrading = Object.entries(report.metrics)
          .filter(([_, m]) => (m as any).trend === "falling" && (m as any).samples > 5);

        if (degrading.length > 0) {
          const [metricName] = degrading[0];
          result.actions.push({
            type: "optimize",
            description: `Detected degrading metric: ${metricName}. Flagged for improvement.`,
            success: true,
            duration: Date.now() - optStart,
          });
          actionsRemaining--;
        }
      } catch (err) { log.caught("non-critical", err); }
    }

    // ── Step 5: Self-Improvement (probabilistic) ─────────────────────────
    if (actionsRemaining > 0 && Math.random() < config.autoImproveChance && !isCircuitOpen("selfImprove")) {
      const improveStart = Date.now();
      try {
        const { analyzeAndPropose, getAnalyzableFiles, listProposals, applyProposal } = await import("./selfImprove");
        const files = getAnalyzableFiles();
        if (files.length > 0) {
          const randomFile = files[Math.floor(Math.random() * files.length)];
          await analyzeAndPropose(randomFile);

          const pending = listProposals("pending");
          result.actions.push({
            type: "improve",
            description: `Analyzed ${randomFile} — ${pending.length} proposals pending`,
            success: true,
            duration: Date.now() - improveStart,
          });
          // v7.1.3: Reset circuit breaker on successful analyze/propose run
          recordSubsystemSuccess("selfImprove");
          actionsRemaining--;
        }
      } catch (err) {
        console.error(`[Orchestrator] Self-improvement error: ${(err as Error).message}`);
        result.errors.push(`Self-improvement failed: ${(err as Error).message}`);
        recordSubsystemFailure("selfImprove");
      }
    }

    // ── Step 6: Memory Consolidation ─────────────────────────────────────
    try {
      const { getConsolidationStats, runConsolidation } = await import("./memoryConsolidation");
      const stats = getConsolidationStats();
      if (stats && stats.trackedMemories > 500) {
        runConsolidation();
        result.actions.push({
          type: "consolidate",
          description: `Memory consolidation run (${stats.trackedMemories} entries)`,
          success: true,
          duration: 0,
        });
      }
    } catch (err) { log.caught("non-critical", err); }


    // ── Step 6b: Skill Graph Learning Pipeline (v6.03) ────────────────────
    try {
      const { runLearningPipeline } = await import("./skillGraph");
      const pipelineResult = runLearningPipeline();
      if (pipelineResult.decayed > 0 || pipelineResult.propagated > 0) {
        log.info(`SkillGraph pipeline: decayed ${pipelineResult.decayed}, propagated ${pipelineResult.propagated}`);
      }
    } catch (err) { log.caught("non-critical", err); }
    // ── Step 7: Self-Model Refresh ───────────────────────────────────────
    try {
      const { refreshSelfModel, recordAction } = await import("./selfModel");
      await refreshSelfModel();
      // v6.12: Only record cycle action when something actually happened (fixes empty cycle noise)
      if (result.actions.length > 0 || result.errors.length > 0) {
        recordAction("orchestrator_cycle", `Cycle #${totalCycles}: ${result.actions.length} actions, ${result.errors.length} errors`);
      }
    } catch (err) { log.caught("non-critical", err); }

    // ── Post-cycle health check ──────────────────────────────────────────
    try {
      const { getHealthReport } = await import("./selfMonitor");
      result.healthAfter = getHealthReport().status;
    } catch {
      result.healthAfter = "unknown";
    }

    // Reset failure counter on success
    if (result.errors.length === 0) {
      consecutiveFailures = 0;
    } else {
      consecutiveFailures++;
      if (consecutiveFailures >= config.maxConsecutiveFailures) {
        console.error(`[Orchestrator] ${consecutiveFailures} consecutive failures — pausing`);
        pause();
      }
    }

  } catch (err) {
    console.error(`[Orchestrator] Cycle crashed: ${(err as Error).message}`);
    result.errors.push(`Cycle crashed: ${(err as Error).message}`);
    consecutiveFailures++;
  }

  result.duration = Date.now() - cycleStart;
  lastCycleResult = result;
  cycleHistory.push(result);
  if (cycleHistory.length > MAX_HISTORY) cycleHistory.shift();

  // v5.34: Record cycle performance for self-monitoring
  recordCyclePerformance(result.duration, result.errors.length === 0);

  if (result.actions.length > 0 || result.errors.length > 0) {
    const cycleSummary =
      `[Orchestrator] Cycle #${totalCycles}: ${result.actions.length} actions, ` +
      `${result.goalsProcessed} goals, ${result.improvementsApplied} improvements, ` +
      `${result.errors.length} errors (${result.duration}ms)` +
      (result.errors.length > 0 ? ` — ${result.errors.join("; ")}` : "");
    console.log(cycleSummary);
  }

  // v6.01: Auto-store significant events as memories for long-term learning
  if (result.improvementsApplied > 0 || result.errors.length > 0) {
    try {
      const { storeMemory } = await import("./memory.js");
      const summary = result.improvementsApplied > 0
        ? `Orchestrator cycle #${totalCycles}: Applied ${result.improvementsApplied} improvement(s). Actions: ${result.actions.map(a => a.description).join("; ")}`
        : `Orchestrator cycle #${totalCycles}: ${result.errors.length} error(s): ${result.errors.join("; ")}`;
      const memType = result.improvementsApplied > 0 ? "self_mod_success" : "self_mod_failure";
      storeMemory(summary, memType, ["orchestrator", `cycle_${totalCycles}`]);
    } catch (err) { log.caught("memory module not available — non-fatal", err); }
  }

  return result;
}

// ── Public API ──────────────────────────────────────────────────────────────

/**
 * Start the autonomy orchestrator.
 */
export function startOrchestrator(overrides?: Partial<OrchestratorConfig>): void {
  if (overrides) config = { ...config, ...overrides };
  // v5.30: Check env var override — AUTONOMY=false to disable
  if (process.env.AUTONOMY === "false") {
    config.enabled = false;
  }
  if (!config.enabled) {
    console.log("[Orchestrator] Disabled by config. Set AUTONOMY=true to enable.");
    return;
  }
  if (_orchActive) return;

  _orchActive = true;
  console.log(`[Orchestrator] Starting — cycle every ${config.cycleIntervalMs}ms`);

  // Run first cycle after a short delay
  setTimeout(() => {
    withOrchestratorLock(() => runCycle()).catch(err => console.error("[Orchestrator] First cycle failed:", err));
  }, 5000);

  // v6.31: Each interval tick acquires the distributed lock before running
  cycleTimer = setInterval(() => {
    if (_orchActive) {
      withOrchestratorLock(() => runCycle()).catch(err => console.error("[Orchestrator] Cycle failed:", err));
    }
  }, config.cycleIntervalMs);
}

/**
 * Stop the orchestrator.
 */
export function stopOrchestrator(): void {
  _orchActive = false;
  if (cycleTimer) {
    clearInterval(cycleTimer);
    cycleTimer = null;
  }
  console.log("[Orchestrator] Stopped");
}

/**
 * Pause without clearing state.
 */
export function pause(): void {
  _orchActive = false;
  if (cycleTimer) {
    clearInterval(cycleTimer);
    cycleTimer = null;
  }
  console.log("[Orchestrator] Paused");
}

/**
 * Resume after pause.
 */
export function resume(): void {
  if (_orchActive) return;
  consecutiveFailures = 0;
  startOrchestrator({ ...config, enabled: true });
}

/**
 * Manually trigger a single cycle (for testing or on-demand).
 */
export async function triggerCycle(): Promise<CycleResult> {
  // v6.31: Acquire lock for manual trigger too
  const r = await withOrchestratorLock(() => runCycle());
  return r.result ?? ({} as CycleResult);
}

/**
 * Get orchestrator configuration.
 */
export function getOrchestratorConfig(): OrchestratorConfig & { isRunning: boolean } {
  return { ...config, isRunning: _orchActive };
}

/**
 * Update orchestrator configuration.
 */
export function setOrchestratorConfig(updates: Partial<OrchestratorConfig>): void {
  config = { ...config, ...updates };
  // Restart with new interval if running
  if (_orchActive && updates.cycleIntervalMs) {
    stopOrchestrator();
    startOrchestrator({ ...config, enabled: true });
  }
}

/**
 * Get orchestrator stats for diagnostics.
 */
export function getOrchestratorStats() {
  return {
    isRunning: _orchActive,
    inSafeMode,
    totalCycles,
    consecutiveFailures,
    avgCycleTimeMs: cycleTimes.length > 0 ? Math.round(cycleTimes.reduce((a, b) => a + b, 0) / cycleTimes.length) : 0,
    lastCycle: lastCycleResult ? {
      id: lastCycleResult.cycleId,
      duration: lastCycleResult.duration,
      actions: lastCycleResult.actions.length,
      errors: lastCycleResult.errors.length,
      healthBefore: lastCycleResult.healthBefore,
      healthAfter: lastCycleResult.healthAfter,
    } : null,
    config: {
      cycleIntervalMs: config.cycleIntervalMs,
      autoImproveChance: config.autoImproveChance,
      maxActionsPerCycle: config.maxActionsPerCycle,
    },
    // v6.03: Circuit breaker status per subsystem
    circuitBreakers: Object.fromEntries(
      Array.from(subsystemCircuits.entries()).map(([name, state]) => [
        name,
        { failures: state.failures, tripped: state.tripped, lastFailure: state.lastFailure }
      ])
    ),
  };
}

/**
 * Get full cycle history.
 */
export function getCycleHistory(limit = 20): CycleResult[] {
  return cycleHistory.slice(-limit);
}

/**
 * Initialize the orchestrator (called from _core/index.ts).
 */
export function initOrchestrator(): void {
  // v5.34: Respect AUTONOMY env var — "true" to enable, "false" to disable
  // Default: enabled (the system is designed for autonomous operation)
  const enabled = process.env.AUTONOMY !== "false";
  const interval = parseInt(process.env.AUTONOMY_CYCLE_MS || process.env.AUTONOMY_INTERVAL || "60000", 10);
  const maxActions = parseInt(process.env.AUTONOMY_MAX_ACTIONS || "5", 10);
  const requireApproval = process.env.AUTONOMY_REQUIRE_APPROVAL === "true";
  startOrchestrator({
    enabled,
    cycleIntervalMs: interval,
    maxActionsPerCycle: maxActions,
    autoImproveChance: requireApproval ? 0 : 0.3, // No auto-improve if approval required
  });
}

/**
 * Andromeda v5.27 — Continuous Self-Improvement Engine
 *
 * Runs a periodic improvement cycle that:
 * 1. Analyzes the codebase for improvement opportunities
 * 2. Generates proposals via selfImprove
 * 3. Applies safe proposals through the guard pipeline
 * 4. Self-reviews changes and rolls back if quality drops
 *
 * Configurable interval (default: every 6 hours).
 * Respects recursion guards and rate limits.
 */

import * as path from "path";
import { createLogger } from "./logger.js";
import { withContinuousImproverLock } from "./redisLock.js";
import { emitRsiEvent } from "./rsiEventBus.js";
import { gitSandbox } from "./gitSandbox.js";
const log = createLogger("continuousImprover");

// ── Configuration ────────────────────────────────────────────────────────────

interface ContinuousImproverConfig {
  enabled: boolean;
  intervalMs: number;           // Default: 6 hours
  maxProposalsPerCycle: number; // Max proposals to generate per cycle
  maxAppliesPerCycle: number;   // Max proposals to apply per cycle
  autoApplyThreshold: number;   // Min confidence to auto-apply (0-1)
  dryRun: boolean;              // If true, generate proposals but don't apply
}

const DEFAULT_CONFIG: ContinuousImproverConfig = {
  enabled: true, // v5.30: Enabled by default — orchestrator coordinates improvement cycles
  intervalMs: 10 * 60 * 1000, // v10.5.7: 10 minutes — was 30 minutes, tripled throughput
  maxProposalsPerCycle: 5,
  maxAppliesPerCycle: 8,  // v10.5.7: increased from 3 → 8 for maximum improvement throughput
  autoApplyThreshold: 0.8,
  dryRun: false,
};

let config: ContinuousImproverConfig = { ...DEFAULT_CONFIG };
let cycleTimer: ReturnType<typeof setInterval> | null = null;
// v6.31: isRunning replaced by withContinuousImproverLock() distributed lock
let _timerActive = false;
let lastCycleAt = 0;
let totalCycles = 0;
let totalProposals = 0;
let totalApplied = 0;
let totalRolledBack = 0;

// ── Cycle History ────────────────────────────────────────────────────────────

interface CycleResult {
  timestamp: number;
  proposalsGenerated: number;
  proposalsApplied: number;
  proposalsRolledBack: number;
  duration: number;
  errors: string[];
}

const cycleHistory: CycleResult[] = [];
const MAX_HISTORY = 50;

// ── Core Improvement Cycle ───────────────────────────────────────────────────

async function runImprovementCycle(): Promise<CycleResult> {
  const start = Date.now();
  const result: CycleResult = {
    timestamp: start,
    proposalsGenerated: 0,
    proposalsApplied: 0,
    proposalsRolledBack: 0,
    duration: 0,
    errors: [],
  };

  try {
    // 1. Check recursion guard
    try {
      const guard = await import("./selfImproveGuard");
      const guardConfig = guard.getGuardConfig();
      if (guardConfig && guardConfig.requireApproval) {
        console.log("[ContinuousImprover] Guard is paused. Skipping cycle.");
        result.duration = Date.now() - start;
        return result;
      }
    } catch (err) { log.caught("guard not available", err); }

    // 2. Analyze codebase for improvement targets
    const { listProposals, analyzeAndPropose } = await import("./selfImprove");

    // Generate new proposals by analyzing a random file
    try {
      const { getAnalyzableFiles } = await import("./selfImprove");
      const files = getAnalyzableFiles();
      if (files.length > 0) {
        // v9.9.0: Analyze 2 files per cycle (was 1) — doubles improvement rate at minimal extra cost
        const shuffled = [...files];
        const crypto = await import('crypto');
        for (let i = shuffled.length - 1; i > 0; i--) {
          const j = crypto.randomBytes(4).readUInt32BE(0) % (i + 1);
          [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
        }
        const filesToAnalyze = shuffled.slice(0, 2);
        for (const randomFile of filesToAnalyze) {
          await analyzeAndPropose(randomFile);
        }
      }
    } catch (err) {
      result.errors.push(`Proposal generation failed: ${(err as Error).message}`);
    }

    // v9.7.0: Eval-driven targeting — submit proposals for degraded benchmark areas
    try {
      const { runEvalDrivenTargeting } = await import("./evalDrivenTargeting.js");
      const targeted = await runEvalDrivenTargeting();
      if (targeted > 0) {
        console.log(`[ContinuousImprover] Eval-driven targeting: ${targeted} targeted proposals submitted`);
      }
    } catch (err) {
      result.errors.push(`Eval-driven targeting failed: ${(err as Error).message}`);
    }

    // v9.7.0: Quality monitor + JSDoc gaps → RSI proposal queue
    try {
      const { runQualityToRSI } = await import("./qualityToRSI.js");
      const { qualityProposals, docProposals } = await runQualityToRSI();
      if (qualityProposals + docProposals > 0) {
        console.log(`[ContinuousImprover] Quality→RSI: ${qualityProposals} quality + ${docProposals} doc proposals submitted`);
      }
    } catch (err) {
      result.errors.push(`Quality→RSI feed failed: ${(err as Error).message}`);
    }

    // v9.8.5: Removed autoApplyHighConfidence to centralize all apply logic
    // in the pending proposals loop below, preventing race conditions.
    let autoResults: any[] = [];

    // 3. Get pending proposals
    const proposals = listProposals().filter((p: any) => p.status === "pending");

    // In v9.8.1 we only count newly generated proposals in totalProposals, but here
    // proposals is the entire pending queue. We'll just report the queue size.
    result.proposalsGenerated = proposals.length;
    // Don't add to totalProposals here, as it double-counts on every cycle

    if (config.dryRun) {
      console.log(`[ContinuousImprover] DRY RUN: ${proposals.length} pending proposals, none applied.`);
      result.duration = Date.now() - start;
      return result;
    }

    // 4. Apply top proposals (up to limit) — with truncation check
    // v9.8.5: Reset any stale 'processing' proposals before applying
    // (proposals stuck in 'processing' from a previous crashed cycle will be reset to 'pending')
    try {
      const { resetStuckProcessingProposals } = await import("./selfImprove");
      resetStuckProcessingProposals();
    } catch { /* non-fatal */ }

    // v9.8.1: Sort by confidence before slicing, so we try the best ones first
    // v11.16.0 Audit 8 Fix A: Use semanticSelfModel.rankProposals() for utility-aware ordering
    let sortedProposals = [...proposals].sort((a: any, b: any) => (b.confidence || 0) - (a.confidence || 0));
    try {
      const { rankProposals } = await import("./semanticSelfModel.js");
      const ranked = rankProposals(proposals.map((p: any) => ({
        moduleName: (p.targetFile || "").replace(/^.*\//, "").replace(/\.ts$/, ""),
        changeType: p.category === "performance" ? "optimize" : p.category === "fix" ? "fix_bug" : "refactor",
        rationale: p.rationale,
      })));
      const rankMap = new Map(ranked.map((r: any) => [r.moduleName, r.rank]));
      sortedProposals = [...proposals].sort((a: any, b: any) => {
        const aName = (a.targetFile || "").replace(/^.*\//, "").replace(/\.ts$/, "");
        const bName = (b.targetFile || "").replace(/^.*\//, "").replace(/\.ts$/, "");
        const aRank = rankMap.get(aName) ?? 999;
        const bRank = rankMap.get(bName) ?? 999;
        if (aRank !== bRank) return aRank - bRank;
        return (b.confidence || 0) - (a.confidence || 0);
      });
    } catch { /* non-fatal — fall back to confidence sort */ }
    const toApply = sortedProposals.slice(0, config.maxAppliesPerCycle);
    const { applyProposal } = await import("./selfImprove");

    // v5.29: Import stream integrity checker for truncation detection
    let checkCompleteness: ((content: string) => { isComplete: boolean; confidence: number; indicators: string[] }) | null = null;
    try {
      const sim = await import("./streamIntegrityMonitor");
      checkCompleteness = sim.checkCompleteness;
    } catch (err) { log.caught("non-fatal — proceed without check", err); }

    for (const proposal of toApply) {
      try {
        // v5.29: Check if proposal content is truncated before applying
        if (checkCompleteness && proposal.proposedContent) {
          const integrity = checkCompleteness(proposal.proposedContent);
          if (!integrity.isComplete && integrity.confidence < 0.5) {
            console.warn(`[ContinuousImprover] Skipping truncated proposal: ${proposal.title || proposal.id} (confidence: ${integrity.confidence.toFixed(2)}, indicators: ${integrity.indicators.join(", ")})`);
            result.proposalsRolledBack++;
            totalRolledBack++;
            result.errors.push(`Truncation detected in ${proposal.id}: ${integrity.indicators.join(", ")}`);
            continue;
          }
        }

        const applyResult = await applyProposal(proposal.id);
        if (applyResult.success) {
          result.proposalsApplied++;
          totalApplied++;
          console.log(`[ContinuousImprover] Applied: ${proposal.title || proposal.id}`);
          emitRsiEvent("proposal:applied", { id: proposal.id, title: proposal.title, targetFile: proposal.targetFile, confidence: proposal.confidence });
          // v11.8.2: Record implicit RLHF feedback for successful applies.
          // A small positive evalDelta (0.1) is recorded immediately; the eval engine
          // will overwrite this with the actual delta after the next benchmark run.
          try {
            const { recordImplicitFeedback } = await import("./rlhfCollector.js");
            recordImplicitFeedback(
              [{ id: proposal.id, targetFile: proposal.targetFile || "unknown", category: proposal.category || "readability", title: proposal.title || proposal.id }],
              0.1
            );
          } catch { /* non-fatal */ }
          // v11.6.0: Append to AI-generated changelog
          try {
            const { appendChangelogEntry } = await import("./aiChangelog.js");
            appendChangelogEntry(
              proposal.id,
              proposal.targetFile || "unknown",
              proposal.title || proposal.id,
              proposal.rationale || "",
              proposal.category || "reliability",
              proposal.impact || "medium",
              proposal.confidence ?? 0,
              proposal.originalSnippet || "",
              proposal.proposedSnippet || ""
            );
          } catch { /* non-fatal */ }
          // v11.10.1: Record learning in selfKnowledgeBase so future proposals
          // for this file get architecture context from past successful changes.
          try {
            const { recordLearning } = await import("./selfKnowledgeBase.js");
            recordLearning({
              title: proposal.title || proposal.id,
              description: `RSI commit: ${proposal.category || "readability"} improvement to ${proposal.targetFile || "unknown"}`,
              lesson: `RSI applied: ${proposal.rationale || "No rationale provided"}`,
              outcome: `Committed with confidence ${(proposal.confidence ?? 0.8).toFixed(2)}`,
              category: "success",
              context: proposal.targetFile || "unknown",
              confidence: proposal.confidence ?? 0.8,
              applicableTo: [proposal.targetFile || "unknown", proposal.category || "readability"],
            });
          } catch { /* non-fatal */ }
          // v11.12.0: Record successful RSI episode in episodic memory
          try {
            const { recordEpisode } = await import("./episodicMemory.js");
            await recordEpisode({
              goal: `RSI improvement: ${proposal.title || proposal.id}`,
              outcome: "success",
              summary: `Applied ${proposal.category || "readability"} improvement to ${proposal.targetFile || "unknown"}: ${proposal.rationale || "No rationale"}`,
            });
          } catch { /* non-fatal */ }
          // v11.13.0 Audit 5 Fix B: Wire learnFromAppliedProposal so knowledgeTransfer DB grows
          try {
            const { learnFromAppliedProposal } = await import("./knowledgeTransfer.js");
            learnFromAppliedProposal({
              id: proposal.id,
              targetFile: proposal.targetFile || "unknown",
              title: proposal.title || proposal.id,
              category: proposal.category || "readability",
              rationale: proposal.rationale || "",
              confidence: proposal.confidence ?? 0.8,
              impact: proposal.impact || "medium",
            });
          } catch { /* non-fatal */ }
          // v11.16.0 Audit 8 Fix B: Record successful RSI decision in selfReflectionEngine
          try {
            const { recordInteraction, logDecision } = await import("./selfReflectionEngine.js");
            recordInteraction("success", `RSI applied: ${proposal.title || proposal.id} → ${proposal.targetFile || "unknown"}`);
            logDecision({
              decisionType: "self_modification",
              context: proposal.targetFile || "unknown",
              alternativesConsidered: [],
              chosenApproach: proposal.title || proposal.id,
              rationale: proposal.rationale || "RSI cycle",
              outcome: "success",
              outcomeNotes: `Confidence: ${(proposal.confidence ?? 0.8).toFixed(2)}`,
            });
          } catch { /* non-fatal */ }
          // v11.20.0 Audit 12 Fix C: Wire updateDecisionOutcome so selfReflectionEngine outcome DB grows
          try {
            const { updateDecisionOutcome } = await import("./selfReflectionEngine.js");
            updateDecisionOutcome(
              proposal.targetFile || "unknown",
              "success",
              `Applied: ${proposal.title || proposal.id} (confidence: ${(proposal.confidence ?? 0.8).toFixed(2)})`
            );
          } catch { /* non-fatal */ }
          // v11.17.0 Audit 9 Fix A: Wire documentSelfImprovement so selfDocumentation DB grows
          try {
            const { documentSelfImprovement } = await import("./selfDocumentation.js");
            documentSelfImprovement(
              proposal.targetFile || "unknown",
              proposal.title || proposal.id,
              proposal.category || "readability",
              "v11.17.0"
            );
          } catch { /* non-fatal */ }
          // v11.17.0 Audit 9 Fix B: Wire broadcastProposal so federatedRsiNetwork peers learn
          try {
            const { broadcastProposal } = await import("./federatedRsiNetwork.js");
            await broadcastProposal({
              id: proposal.id,
              targetFile: proposal.targetFile || "unknown",
              category: proposal.category || "readability",
              rationale: proposal.rationale || "",
              confidence: proposal.confidence ?? 0.8,
              proposedContent: proposal.proposedSnippet || "",
              originalContent: proposal.originalSnippet || "",
            });
          } catch { /* non-fatal */ }
          // v11.19.0 Audit 11 Fix C: Wire recordObservation so longTermMemoryConsolidation DB grows
          try {
            const { recordObservation } = await import("./longTermMemoryConsolidation.js");
            recordObservation({
              cycleId: `cycle-${totalCycles}`,
              timestamp: Date.now(),
              targetFile: proposal.targetFile || "unknown",
              changeDescription: proposal.title || proposal.id,
              diff: proposal.diff || "",
              evalScoreBefore: 0,
              evalScoreAfter: proposal.confidence ?? 0.8,
              accepted: true,
            });
          } catch { /* non-fatal */ }
        } else {
          result.proposalsRolledBack++;
          totalRolledBack++;
          console.warn(`[ContinuousImprover] Rejected: ${proposal.title || proposal.id} — ${applyResult.message}`);
          emitRsiEvent("proposal:rejected", { id: proposal.id, title: proposal.title, reason: applyResult.message });
          // v11.6.0: Record rejection feedback so future proposals for this file learn from this failure
          try {
            const { recordRejectionFeedback } = await import("./proposalFeedback.js");
            recordRejectionFeedback(
              proposal.id,
              proposal.targetFile || "unknown",
              proposal.title || proposal.id,
              proposal.originalSnippet || "",
              proposal.proposedSnippet || "",
              applyResult.message || "unknown"
            );
          } catch { /* non-fatal */ }
          // v11.12.0: Record failed RSI episode in episodic memory
          try {
            const { recordEpisode } = await import("./episodicMemory.js");
            await recordEpisode({
              goal: `RSI improvement: ${proposal.title || proposal.id}`,
              outcome: "failure",
              summary: `Rejected ${proposal.category || "readability"} proposal for ${proposal.targetFile || "unknown"}: ${applyResult.message || "unknown reason"}`,
              failedStep: "guardedApply",
            });
          } catch { /* non-fatal */ }
          // v11.16.0 Audit 8 Fix B: Record failed RSI decision in selfReflectionEngine
          try {
            const { recordInteraction, logDecision } = await import("./selfReflectionEngine.js");
            recordInteraction("failure", `RSI rejected: ${proposal.title || proposal.id} — ${applyResult.message || "unknown"}`);
            logDecision({
              decisionType: "self_modification",
              context: proposal.targetFile || "unknown",
              alternativesConsidered: [],
              chosenApproach: `Reject: ${proposal.title || proposal.id}`,
              rationale: applyResult.message || "guardedApply rejected",
              outcome: "failure",
              outcomeNotes: applyResult.message,
            });
          } catch { /* non-fatal */ }
        }
      } catch (err) {
        const errMsg = (err as Error).message || String(err);
        result.errors.push(`Apply failed for ${proposal.id}: ${errMsg}`);
        console.error(`[ContinuousImprover] EXCEPTION applying ${proposal.title || proposal.id}: ${errMsg}`);
        // Ensure the proposal is not left stuck in 'processing' after an exception
        try {
          const { rejectProposal } = await import('./selfImprove');
          rejectProposal(proposal.id);
        } catch { /* best effort */ }
      }
      // Yield to the event loop to prevent blocking during tight apply loops
      await new Promise(r => setImmediate(r));
    }

    // 5. Post-cycle: validate all changes with TypeScript check + smoke tests + behavioral tests
    if (result.proposalsApplied > 0) {
      try {
        const { spawnSync } = await import("child_process");
        const serverDir = path.resolve(process.cwd());

        // v11.2.0: R9 Post-Apply Git Diff Safety Check
        // Scans every modified file in the git working tree for R9 violations:
        //   1. Test files must NEVER be modified (constitution §filePatterns)
        //   2. .toBeTruthy()/.toBeFalsy() must never replace null/undefined checks
        // This is the ROOT CAUSE FIX for the ContinuousImprover R9 bypass:
        // secondary test-file changes generated alongside source changes were
        // not going through the per-proposal constitution check.
        try {
          // v11.4.0: All git calls now go through gitSandbox() whitelist
          const diffOutput = gitSandbox(
            "git diff --name-only HEAD",
            { cwd: serverDir, timeout: 10000, encoding: "utf-8", stdio: "pipe" }
          ).trim();
          if (diffOutput) {
            const modifiedFiles = diffOutput.split("\n").filter(Boolean);
            // Rule 1: Roll back any test file modifications immediately
            const testFileViolations = modifiedFiles.filter(
              f => f.endsWith(".test.ts") || f.endsWith(".test.js") || f.endsWith(".spec.ts") || f.endsWith(".spec.js")
            );
            if (testFileViolations.length > 0) {
              const filesArg = testFileViolations.map(f => `"${f}"`).join(" ");
              gitSandbox(`git checkout HEAD -- ${filesArg}`, { cwd: serverDir, timeout: 10000, stdio: "pipe", encoding: "utf-8" });
              console.warn(`[ContinuousImprover] R9 VIOLATION: Rolled back ${testFileViolations.length} test file modification(s): ${testFileViolations.join(", ")}`);
              result.errors.push(`R9 violation: test files modified and rolled back: ${testFileViolations.join(", ")}`);
            }
            // Rule 2: Scan non-test modified files for .toBeTruthy()/.toBeFalsy() additions
            const sourceFiles = modifiedFiles.filter(f => !testFileViolations.includes(f));
            for (const file of sourceFiles) {
              try {
                const fileDiff = gitSandbox(
                  `git diff HEAD -- "${file}"`,
                  { cwd: serverDir, timeout: 5000, encoding: "utf-8", stdio: "pipe" }
                );
                const addedLines = fileDiff.split("\n").filter(l => l.startsWith("+") && !l.startsWith("+++"));
                const r9Violation = addedLines.some(l =>
                  l.includes(".toBeTruthy()") || l.includes(".toBeFalsy()")
                );
                if (r9Violation) {
                  gitSandbox(`git checkout HEAD -- "${file}"`, { cwd: serverDir, timeout: 5000, stdio: "pipe", encoding: "utf-8" });
                  console.warn(`[ContinuousImprover] R9 VIOLATION in ${file}: weakened assertion (.toBeTruthy/.toBeFalsy) — rolled back.`);
                  result.errors.push(`R9 violation in ${file}: weakened assertion rolled back`);
                }
              } catch { /* best effort per-file scan */ }
            }
          }
        } catch (r9Err: any) {
          // Non-fatal: if git is unavailable, log and continue
          console.warn("[ContinuousImprover] R9 git diff check unavailable (non-fatal):", r9Err.message?.slice(0, 100));
        }

        console.log(`[ContinuousImprover] Running TypeScript check after ${result.proposalsApplied} applies...`);
        // v9.8.5: Use node_modules/.bin/tsc directly — npx is not available in all environments
        // v10.3.1: Use spawnSync with args array instead of execSync with shell string to avoid DEP0190.
        const tscBin = path.resolve(serverDir, "node_modules", ".bin", "tsc");
        const fs2 = require("fs");
        const [tscExe, tscArgs] = fs2.existsSync(tscBin)
          ? [tscBin, ["--noEmit"]]
          : ["node", [require("path").resolve(serverDir, "node_modules", "typescript", "bin", "tsc"), "--noEmit"]];
        const tscResult = spawnSync(tscExe, tscArgs, { cwd: serverDir, timeout: 60000, stdio: "pipe", encoding: "utf-8" });
        if (tscResult.status !== 0) { throw new Error(tscResult.stderr || tscResult.stdout || "TypeScript check failed"); }
        console.log("[ContinuousImprover] TypeScript check PASSED. Changes are valid.");

        // v11.0.3: Run full Vitest test suite after TypeScript check.
        // The guard only runs targeted tests for the modified file — this catches
        // regressions in other tests caused by behavioral changes in the modified file.
        try {
          const { spawnSync: spawnSync2 } = await import("child_process");
          console.log(`[ContinuousImprover] Running full test suite to verify no regressions...`);
          const vitestBin = path.resolve(serverDir, "node_modules", ".bin", "vitest");
          const vitestResult = spawnSync2(
            "sh", ["-c", `pnpm exec vitest run --reporter=verbose 2>&1`],
            { cwd: serverDir, timeout: 300000, stdio: "pipe", encoding: "utf-8" }
          );
          if (vitestResult.status !== 0) {
            const failOutput = (vitestResult.stdout || vitestResult.stderr || "").slice(-2000);
            throw new Error(`Full test suite FAILED after apply:\n${failOutput}`);
          }
          console.log("[ContinuousImprover] Full test suite PASSED. All regressions clear.");
        } catch (testErr: any) {
          if (testErr.message.includes('Full test suite FAILED')) throw testErr;
          console.warn('[ContinuousImprover] Full test suite unavailable (non-fatal):', testErr.message);
        }
        // v5.97: Run smoke tests after TypeScript check
        try {
          const { runSmokeTests } = await import("./self/smoke_test_runner.js");
          const smokeResult = await runSmokeTests(serverDir);
          if (smokeResult.rollbackRecommended) {
            throw new Error(`Smoke tests FAILED: ${smokeResult.failed}/${smokeResult.totalTests} tests failed`);
          }
          console.log(`[ContinuousImprover] Smoke tests PASSED: ${smokeResult.passed}/${smokeResult.totalTests}`);
        } catch (smokeErr: any) {
          if (smokeErr.message.includes('Smoke tests FAILED')) throw smokeErr;
          console.warn('[ContinuousImprover] Smoke tests unavailable (non-fatal):', smokeErr.message);
        }
        // 6. Trigger hot-reload so changes take effect without full restart
        try {
          const http = await import("http");
          const port = parseInt(process.env.PORT || "3000");
          const reloadReq = http.request({ hostname: "127.0.0.1", port, path: "/api/module/reload", method: "POST", headers: { "Content-Type": "application/json" } });
          reloadReq.write(JSON.stringify({ module: "./selfImprove" }));
          reloadReq.end();
          console.log("[ContinuousImprover] Hot-reload triggered for modified modules.");
        } catch (err) { log.caught("non-fatal -- server will pick up changes on next import", err); }

        // v9.9.0: Push main directly to GitHub after each successful cycle.
        // Changes are already committed to main by applyProposal().
        // Pushing triggers CI (RSI Validate + CI build) automatically.
        // No branches or PRs needed — Andromeda owns main directly.
        if (process.env.GITHUB_TOKEN && process.env.GITHUB_REPO) {
          try {
            // v11.4.0: git push now goes through gitSandbox() whitelist
            const cwd = process.cwd();
            const gitEnv = { ...process.env, GIT_AUTHOR_NAME: "Andromeda AI", GIT_AUTHOR_EMAIL: "andromeda@local", GIT_COMMITTER_NAME: "Andromeda AI", GIT_COMMITTER_EMAIL: "andromeda@local" };
            const token = process.env.GITHUB_TOKEN;
            // Sanitize repo name — only allow alphanumeric, /, -, .
            const repo = (process.env.GITHUB_REPO || "").replace(/[^a-zA-Z0-9/_.-]/g, "");
            const remoteUrl = `https://${token}@github.com/${repo}.git`;
            gitSandbox(`git push "${remoteUrl}" main`, { cwd, env: gitEnv, encoding: "utf-8", stdio: "pipe", timeout: 30000 });
            console.log(`[ContinuousImprover] Pushed ${result.proposalsApplied} improvement(s) to origin/main — CI triggered.`);
          } catch (pushErr: any) {
            // Non-fatal — push failure should never block the improvement cycle
            // Sanitize all potential token patterns from all error output channels
            const rawMsg = (pushErr.stderr || pushErr.stdout || pushErr.message || pushErr.toString());
            const safeMsg = rawMsg
              .replace(/ghp_[A-Za-z0-9]{36}/g, "ghp_***")
              .replace(/gho_[A-Za-z0-9]{36}/g, "gho_***")
              .replace(/ghu_[A-Za-z0-9]{36}/g, "ghu_***")
              .replace(/ghs_[A-Za-z0-9]{36}/g, "ghs_***")
              .replace(/ghr_[A-Za-z0-9]{36}/g, "ghr_***")
              .replace(/https:\/\/[^@\s]+@github\.com/g, "https://***@github.com")
              .replace(/:[^:@\s]+@github\.com/g, ":***@github.com");
            console.warn(`[ContinuousImprover] Git push failed (non-fatal): ${safeMsg.slice(0, 200)}`);
          }
        }
      } catch (tsErr: any) {
        // TypeScript check failed -- rollback all proposals applied this cycle
        console.error(`[ContinuousImprover] TypeScript check FAILED after applies. Rolling back...`);
        result.errors.push(`Post-apply TS check failed: ${(tsErr.stderr || tsErr.message || "").toString().slice(0, 200)}`);
        try {
                    // v11.4.0: git checkout rollback now goes through gitSandbox() whitelist
          const filesToRollback = new Set<string>();
          // v11.10.1: autoResults is always empty (legacy dead code) — use toApply directly
          for (const p of toApply) {
            const wasApplied = listProposals().find((sp: any) => sp.id === p.id)?.status === "applied";
            if (wasApplied) filesToRollback.add(p.targetFile);
          }
          if (filesToRollback.size > 0) {
            const filesArg = Array.from(filesToRollback).map(f => `"${f}"`).join(" ");
            gitSandbox(`git checkout HEAD -- ${filesArg}`, { cwd: process.cwd(), timeout: 10000, stdio: "pipe", encoding: "utf-8" });
            console.log(`[ContinuousImprover] Rolled back specific files: ${Array.from(filesToRollback).join(", ")}`);
          } else {
            console.log("[ContinuousImprover] No specific files identified for rollback.");
          }
          result.proposalsRolledBack += result.proposalsApplied;
          result.proposalsApplied = 0;
        } catch (rollbackErr) {
          result.errors.push(`Rollback failed: ${(rollbackErr as Error).message}`);
        }
      }
    }

    // 7. Post-cycle health check
    try {
      const { getHealthReport } = await import("./selfMonitor");
      const report = getHealthReport();
      if (report && report.status !== "healthy") {
        console.warn(`[ContinuousImprover] Post-cycle health: ${report.status}. Pausing next cycle.`);
      }
    } catch (err) { log.caught("non-fatal", err); }

  } catch (err) {
    result.errors.push(`Cycle error: ${(err as Error).message}`);
    console.error("[ContinuousImprover] Cycle failed:", (err as Error).message);
  }

  result.duration = Date.now() - start;
  lastCycleAt = Date.now();
  totalCycles++;
  cycleHistory.push(result);
  if (cycleHistory.length > MAX_HISTORY) cycleHistory.shift();

  // v11.13.0 Audit 5 Fix A: Prune stale failure patterns every 10 cycles to prevent unbounded DB growth
  if (totalCycles % 10 === 0) {
    try {
      const { pruneOldFailures } = await import("./failurePatternMemory.js");
      const pruned = pruneOldFailures();
      if (pruned > 0) console.log(`[ContinuousImprover] Pruned ${pruned} stale failure pattern(s) from memory.`);
    } catch { /* non-fatal */ }
  }

  // v11.15.0 Audit 7 Fix B: Wire generateImprovementGoals so autonomousGoalGenerator DB grows
  // Run every 5 cycles to generate self-directed improvement goals from recent RSI history
  if (totalCycles % 5 === 0) {
    try {
      const { generateImprovementGoals } = await import("./autonomousGoalGenerator.js");
      const goalResult = await generateImprovementGoals();
      if (goalResult.goals.length > 0) {
        console.log(`[ContinuousImprover] Generated ${goalResult.goals.length} autonomous improvement goal(s) from cycle #${totalCycles}.`);
      }
    } catch { /* non-fatal — autonomousGoalGenerator may not be available */ }
  }

  // v11.15.0 Audit 7 Fix C: Wire processPendingGaps so capabilityBootstrapper queue is consumed
  // Run every 20 cycles to process any pending capability gaps registered during RSI
  if (totalCycles % 20 === 0) {
    try {
      const { processPendingGaps } = await import("./capabilityBootstrapper.js");
      await processPendingGaps();
    } catch { /* non-fatal — capabilityBootstrapper may not be available */ }
  }

  // v11.16.0 Audit 8 Fix C: Wire triggerReflection so selfReflectionEngine synthesizes lessons
  // Run every 3 cycles — reflection is lightweight but should not run every cycle
  if (totalCycles % 3 === 0) {
    try {
      const { triggerReflection } = await import("./selfReflectionEngine.js");
      await triggerReflection();
    } catch { /* non-fatal */ }
  }

  // v11.18.0 Audit 10 Fix A: Wire analyzeAndImprovePrompts so promptEngineer DB grows
  // Run every 15 cycles to evolve prompt patterns from RSI outcomes
  if (totalCycles % 15 === 0) {
    setImmediate(async () => {
      try {
        const { analyzeAndImprovePrompts } = await import("./promptEngineer.js");
        await analyzeAndImprovePrompts();
      } catch { /* non-fatal */ }
    });
  }

  // v11.18.0 Audit 10 Fix B: Wire runNightlyFineTuningCycle so local fine-tuning DB grows
  // Run every 50 cycles — fine-tuning is expensive, run infrequently
  if (totalCycles % 50 === 0) {
    setImmediate(async () => {
      try {
        const { runNightlyFineTuningCycle } = await import("./continuousFineTuning.js");
        await runNightlyFineTuningCycle();
      } catch { /* non-fatal */ }
    });
  }

  // v11.19.0 Audit 11 Fix B: Wire runLongTermConsolidation so long-term memory patterns grow
  // Run every 7 cycles — consolidation extracts patterns from recent RSI diffs
  if (totalCycles % 7 === 0) {
    setImmediate(async () => {
      try {
        const { runLongTermConsolidation } = await import("./longTermMemoryConsolidation.js");
        const result = await runLongTermConsolidation();
        if (result.newPatternsFound > 0) {
          console.log(`[ContinuousImprover] Long-term consolidation: ${result.newPatternsFound} new pattern(s) extracted from cycle #${totalCycles}.`);
        }
      } catch { /* non-fatal */ }
    });
  }

  // v11.20.0 Audit 12 Fix B: Wire consolidateKnowledge so unifiedKnowledge DB stays current
  // Run every 25 cycles — knowledge consolidation deduplicates and merges all knowledge sources
  if (totalCycles % 25 === 0) {
    setImmediate(async () => {
      try {
        const { consolidateKnowledge } = await import("./unifiedKnowledge.js");
        const kr = await consolidateKnowledge();
        if (kr.merged > 0 || kr.removed > 0) {
          console.log(`[ContinuousImprover] Knowledge consolidation: ${kr.merged} merged, ${kr.removed} removed across ${kr.sourcesProcessed.length} source(s).`);
        }
      } catch { /* non-fatal */ }
    });
  }

  // v11.23.0 Audit 15 Fix A: Wire clearAllCaches so memory footprint stays stable during long RSI runs
  // Run every 100 cycles to completely clear all non-essential caches
  if (totalCycles % 100 === 0) {
    try {
      const { clearAllCaches } = await import("./cache.js");
      clearAllCaches();
      console.log(`[ContinuousImprover] Cleared all caches at cycle #${totalCycles} to prevent OOM.`);
    } catch { /* non-fatal */ }
  }

  // v11.23.0 Audit 15 Fix B: Wire triggerCycle from autonomyOrchestrator to ensure deep self-reflection
  // Run every 12 cycles to trigger a full autonomy cycle which analyzes logs and updates goals
  if (totalCycles % 12 === 0) {
    setImmediate(async () => {
      try {
        const { triggerCycle } = await import("./autonomyOrchestrator.js");
        await triggerCycle();
      } catch { /* non-fatal */ }
    });
  }

  // v11.20.0 Audit 12 Fix A: Wire recordRsiCycle so telemetry DB receives every RSI cycle sample
  try {
    const { recordRsiCycle } = await import("./telemetry.js");
    recordRsiCycle({
      cycleId: `cycle-${totalCycles}`,
      durationMs: result.duration,
      proposalsGenerated: result.proposalsGenerated,
      proposalsApplied: result.proposalsApplied,
      evalScore: null,
    });
  } catch { /* non-fatal */ }

  console.log(`[ContinuousImprover] Cycle #${totalCycles} complete: ${result.proposalsApplied} applied, ${result.proposalsRolledBack} rolled back (${result.duration}ms)`);
  emitRsiEvent("cycle:complete", { cycleNumber: totalCycles, proposalsApplied: result.proposalsApplied, proposalsRolledBack: result.proposalsRolledBack, duration: result.duration, errors: result.errors.length });
  return result;
}

// ── Public API ───────────────────────────────────────────────────────────────

export function startContinuousImprover(overrides?: Partial<ContinuousImproverConfig>): void {
  if (overrides) config = { ...config, ...overrides };
  if (!config.enabled) {
    console.log("[ContinuousImprover] Disabled. Set enabled: true to activate.");
    return;
  }
  if (_timerActive) return;

  // v6.31: Each interval tick acquires the distributed lock before running
  _timerActive = true;

  // v9.8.1: Run an initial cycle shortly after startup to process pending proposals
  setTimeout(() => {
    if (_timerActive) {
      withContinuousImproverLock(() => runImprovementCycle()).catch(err =>
        console.warn("[ContinuousImprover] Initial cycle skipped (lock busy or error):", (err as Error).message)
      );
    }
  }, 15000); // 15 seconds after startup

  cycleTimer = setInterval(() => {
    withContinuousImproverLock(() => runImprovementCycle()).catch(err =>
      console.warn("[ContinuousImprover] Cycle skipped (lock busy or error):", (err as Error).message)
    );
  }, config.intervalMs);
  console.log(`[ContinuousImprover] Started. Interval: ${config.intervalMs / 1000 / 60}min, maxApplies: ${config.maxAppliesPerCycle}`);
}

export function stopContinuousImprover(): void {
  if (cycleTimer) clearInterval(cycleTimer);
  cycleTimer = null;
  _timerActive = false;
  // v6.31: No isRunning flag to clear — lock releases automatically
  console.log("[ContinuousImprover] Stopped.");
}

export function triggerCycleNow(): Promise<CycleResult> {
  // v6.31: Acquire lock for manual trigger too
  return withContinuousImproverLock(() => runImprovementCycle()).then(r => r.result ?? ({} as CycleResult));
}

export function getImproverStats(): {
  enabled: boolean;
  running: boolean;
  totalCycles: number;
  totalProposals: number;
  totalApplied: number;
  totalRolledBack: number;
  lastCycleAt: number;
  intervalMs: number;
  recentHistory: CycleResult[];
} {
  return {
    enabled: config.enabled,
    running: _timerActive,
    totalCycles,
    totalProposals,
    totalApplied,
    totalRolledBack,
    lastCycleAt,
    intervalMs: config.intervalMs,
    recentHistory: cycleHistory.slice(-10),
  };
}

export function updateImproverConfig(updates: Partial<ContinuousImproverConfig>): void {
  config = { ...config, ...updates };
  if (_timerActive && updates.intervalMs) {
    // Restart with new interval
    stopContinuousImprover();
    startContinuousImprover();
  }
}

/**
 * Andromeda v5.28 — Self-Model (Runtime Meta-Cognitive State)
 *
 * Provides a live, queryable model of Andromeda's current state:
 * - What capabilities are available and their health
 * - What goals are active and their progress
 * - Current resource usage (tokens, memory, API calls)
 * - Recent activity and performance trends
 *
 * This enables Andromeda to answer "what am I?" and "what can I do?"
 * without scanning all files — it's a cached, real-time self-representation.
 */

import { existsSync, readFileSync, writeFileSync } from "fs";
import { getContextWindow } from "./modelRegistry";
import { join } from "path";

// v6.03: Read version from package.json to prevent version drift
function readPackageVersion(): string {
  try {
    const pkgPath = join(process.cwd(), "package.json");
    const pkg = JSON.parse(readFileSync(pkgPath, "utf-8"));
    return pkg.version || "unknown";
  } catch {
    return "unknown";
  }
}
const PACKAGE_VERSION = readPackageVersion();

// v5.29: Static imports for capability discovery (dynamic import/require doesn't work in esbuild bundle)
import * as _selfHeal from "./selfHeal";
import * as _selfModify from "./selfModify";
import * as _selfImprove from "./selfImprove";
import * as _recursiveGoals from "./recursiveGoals";
import * as _streamIntegrityMonitor from "./streamIntegrityMonitor";
import * as _tokenBudgetManager from "./tokenBudgetManager";
import * as _hotReload from "./hotReload";
import * as _gracefulDegradation from "./gracefulDegradation";
import * as _recursionGuard from "./recursionGuard";
import * as _skillGraph from "./skillGraph";
import * as _consensusEngine from "./consensusEngine";
import * as _continuousImprover from "./continuousImprover";
import * as _selfMonitor from "./selfMonitor";
import * as _selfKnowledgeBase from "./selfKnowledgeBase";
// v5.34: Lazy import to break circular dependency (autonomyOrchestrator ↔ selfModel)
let _autonomyOrchestrator: any = null;
async function getAutonomyOrchestrator() {
  if (!_autonomyOrchestrator) {
    _autonomyOrchestrator = await import("./autonomyOrchestrator");
